import { useState, useEffect, useMemo } from 'react';
import { dbService, Query } from '../lib/appwrite';
import { X, Download, FileSpreadsheet, TrendingUp, TrendingDown, Wallet } from 'lucide-react';
import { format } from 'date-fns';
import * as XLSX from 'xlsx';
import toast from 'react-hot-toast';

const fmt = (n) => (Number(n) || 0).toLocaleString('en-IN', { maximumFractionDigits: 2 });

const LABEL_CONFIG = {
    distributor: {
        debit: 'Total Deposited',
        credit: 'Total Distributed',
        balance: 'Balance in Hand',
        debitIcon: TrendingUp,
        creditIcon: TrendingDown,
        balanceIcon: Wallet,
        debitColor: '#4a9eff',
        creditColor: '#ff5460',
        balanceColor: '#a78bfa',
    },
    collection: {
        debit: 'Total',
        credit: 'Paid',
        balance: 'Balance',
        debitIcon: TrendingUp,
        creditIcon: TrendingDown,
        balanceIcon: Wallet,
        debitColor: '#4a9eff',
        creditColor: '#ff5460',
        balanceColor: '#25D366',
    },
    conversion_sar: {
        debit: 'Total Given',
        credit: 'Total Returned',
        balance: 'Balance',
        debitIcon: TrendingUp,
        creditIcon: TrendingDown,
        balanceIcon: Wallet,
        debitColor: '#4a9eff',
        creditColor: '#ff5460',
        balanceColor: '#25D366',
    },
    conversion_aed: {
        debit: 'Total Given',
        credit: 'Total Returned',
        balance: 'Balance',
        debitIcon: TrendingUp,
        creditIcon: TrendingDown,
        balanceIcon: Wallet,
        debitColor: '#f5a623',
        creditColor: '#ff5460',
        balanceColor: '#25D366',
    },
};

export default function LedgerModal({ agent, onClose }) {
    const [entries, setEntries] = useState([]);
    const [loading, setLoading] = useState(true);
    const [currencyFilter, setCurrencyFilter] = useState('All');
    const type = agent?.type || 'collection';

    const cfg = LABEL_CONFIG[type] || LABEL_CONFIG.collection;

    const fetchEntries = async () => {
        setLoading(true);
        try {
            const res = await dbService.listLedgerEntries([
                Query.equal('agent_id', agent.$id),
                Query.orderDesc('createdAt'),
            ]);
            const filtered = res.documents.filter(e => !e.agent_type || e.agent_type === agent.type);
            setEntries(filtered);
        } catch (e) {
            toast.error('Failed to load: ' + e.message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (agent) fetchEntries();
    }, [agent]);

    const allEntries = useMemo(() => {
        return entries.map(e => ({
            _id: e.$id,
            _date: e.createdAt,
            _type: e.type,
            particular: e.description,
            reference_type: e.reference_type,
            reference_id: e.reference_id,
            currency: e.currency,
            amt: e.type === 'debit' ? Number(e.amount) : -Number(e.amount),
            credit: e.type === 'credit' ? Number(e.amount) : 0,
            debit: e.type === 'debit' ? Number(e.amount) : 0,
        }));
    }, [entries]);

    const filtered = allEntries.filter(r => currencyFilter === 'All' || r.currency === currencyFilter);

    // Totals per currency
    const allCurrencies = ['SAR', 'AED', 'INR'];
    const displayCurrencies = currencyFilter === 'All' ? allCurrencies : [currencyFilter];

    const totals = {};
    allCurrencies.forEach(cur => {
        const curEntries = allEntries.filter(e => e.currency === cur);
        const totalDebit = curEntries.reduce((a, e) => a + Number(e.debit || 0), 0);
        const totalCredit = curEntries.reduce((a, e) => a + Number(e.credit || 0), 0);
        let bal = totalDebit - totalCredit;
        if (Math.abs(bal) < 0.001) bal = 0;
        totals[cur] = { debit: totalDebit, credit: totalCredit, balance: bal };
    });

    // Running balance calculation (ascending, then reverse for display)
    const sortedEntries = [...filtered].sort((a, b) => new Date(a._date) - new Date(b._date));
    const runningBal = { SAR: 0, AED: 0, INR: 0 };
    const entriesWithBalance = sortedEntries.map(entry => {
        const cur = entry.currency;
        if (cur && runningBal[cur] !== undefined) {
            runningBal[cur] += Number(entry.debit || 0) - Number(entry.credit || 0);
            if (Math.abs(runningBal[cur]) < 0.001) runningBal[cur] = 0;
        }
        return { ...entry, runningBalance: cur ? runningBal[cur] : 0 };
    }).reverse();

    const exportToExcel = () => {
        const rows = entriesWithBalance.map((r, i) => ({
            '#': entriesWithBalance.length - i,
            'Date': r._date ? format(new Date(r._date), 'dd-MM-yyyy HH:mm') : '',
            'Particular': r.particular,
            'Type': r._type.toUpperCase(),
            'Currency': r.currency,
            [cfg.debit]: r.debit || '',
            [cfg.credit]: r.credit || '',
            'Balance': r.runningBalance,
        }));
        const ws = XLSX.utils.json_to_sheet(rows);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, `${agent.name}_Ledger`);
        XLSX.writeFile(wb, `Ledger_${agent.name}_${format(new Date(), 'yyyy-MM-dd')}.xlsx`);
        toast.success(`Downloaded ledger`);
    };

    if (!agent) return null;

    return (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
            <div className="modal" style={{ maxWidth: '900px', width: '95%', maxHeight: '95vh', display: 'flex', flexDirection: 'column' }}>
                {/* ÔöÇÔöÇ Header ÔöÇÔöÇ */}
                <div className="modal-header" style={{ paddingBottom: 16 }}>
                    <div>
                        <h3 className="modal-title" style={{ fontSize: 24 }}>{agent.name}</h3>
                        <div style={{ fontSize: '13px', color: 'var(--text-muted)', marginTop: '4px' }}>
                            {agent.type === 'distributor' ? 'Distributor' : agent.type === 'collection' ? 'Collection Agent' : 'Conversion Agent'} ÔÇö {entries.length} entries
                        </div>
                    </div>
                    <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                        <button className="btn btn-outline btn-sm" onClick={exportToExcel} title="Export to Excel">
                            <Download size={14} /> Excel
                        </button>
                        <button className="close-btn" onClick={onClose}><X size={20} /></button>
                    </div>
                </div>

                <div className="modal-body" style={{ flex: 1, overflowY: 'auto', padding: '20px 24px', background: 'var(--bg-color)' }}>
                    {loading ? (
                        <div className="loading-screen" style={{ minHeight: '300px' }}>
                            <div className="spinner" /><p>LoadingÔÇª</p>
                        </div>
                    ) : (
                        <>
                            {/* ÔöÇÔöÇ Summary Report Cards ÔöÇÔöÇ */}
                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16, marginBottom: 24 }}>
                                {/* Deposited / Total Given */}
                                <div className="card" style={{ padding: '20px 18px', border: `1px solid ${cfg.debitColor}30`, background: `linear-gradient(135deg, ${cfg.debitColor}08, transparent)` }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
                                        <div style={{ width: 32, height: 32, borderRadius: 8, background: `${cfg.debitColor}20`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                            <TrendingUp size={16} color={cfg.debitColor} />
                                        </div>
                                        <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                                            + {cfg.debit}
                                        </div>
                                    </div>
                                    {displayCurrencies.map(cur => {
                                        const t = totals[cur];
                                        return (
                                            <div key={cur} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                                                <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-muted)' }}>{cur}</span>
                                                <span style={{ fontSize: 15, fontWeight: 800, color: cfg.debitColor }}>{fmt(t.debit)}</span>
                                            </div>
                                        );
                                    })}
                                </div>

                                {/* Distributed / Paid / Returned */}
                                <div className="card" style={{ padding: '20px 18px', border: `1px solid ${cfg.creditColor}30`, background: `linear-gradient(135deg, ${cfg.creditColor}08, transparent)` }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
                                        <div style={{ width: 32, height: 32, borderRadius: 8, background: `${cfg.creditColor}20`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                            <TrendingDown size={16} color={cfg.creditColor} />
                                        </div>
                                        <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                                            ÔêÆ {cfg.credit}
                                        </div>
                                    </div>
                                    {displayCurrencies.map(cur => {
                                        const t = totals[cur];
                                        return (
                                            <div key={cur} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                                                <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-muted)' }}>{cur}</span>
                                                <span style={{ fontSize: 15, fontWeight: 800, color: cfg.creditColor }}>{fmt(t.credit)}</span>
                                            </div>
                                        );
                                    })}
                                </div>

                                {/* Balance in Hand */}
                                <div className="card" style={{ padding: '20px 18px', border: `1px solid ${cfg.balanceColor}40`, background: `linear-gradient(135deg, ${cfg.balanceColor}10, transparent)` }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
                                        <div style={{ width: 32, height: 32, borderRadius: 8, background: `${cfg.balanceColor}25`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                            <Wallet size={16} color={cfg.balanceColor} />
                                        </div>
                                        <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                                            {cfg.balance}
                                        </div>
                                    </div>
                                    {displayCurrencies.map(cur => {
                                        const t = totals[cur];
                                        const balColor = t.balance >= 0 ? cfg.balanceColor : 'var(--status-failed)';
                                        return (
                                            <div key={cur} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
                                                <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-muted)' }}>{cur}</span>
                                                <span style={{ fontSize: 15, fontWeight: 800, color: balColor }}>
                                                    {t.balance >= 0 ? '+' : 'ÔêÆ'}{fmt(Math.abs(t.balance))}
                                                </span>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            {/* ÔöÇÔöÇ Currency Filter ÔöÇÔöÇ */}
                            <div className="flex items-center justify-between mb-4">
                                <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-muted)' }}>
                                    All Transactions
                                </span>
                                <div className="flex gap-1" style={{ background: 'rgba(255,255,255,0.03)', padding: 4, borderRadius: 8 }}>
                                    {['All', 'SAR', 'AED', 'INR'].map(c => (
                                        <button
                                            key={c}
                                            onClick={() => setCurrencyFilter(c)}
                                            style={{
                                                padding: '6px 16px',
                                                fontSize: 13,
                                                fontWeight: currencyFilter === c ? 700 : 500,
                                                borderRadius: 6,
                                                border: 'none',
                                                color: currencyFilter === c ? '#fff' : 'var(--text-muted)',
                                                background: currencyFilter === c
                                                    ? (c === 'SAR' ? '#4a9eff' : c === 'AED' ? 'var(--brand-gold)' : c === 'INR' ? '#a78bfa' : 'var(--brand-accent)')
                                                    : 'transparent',
                                                cursor: 'pointer',
                                                transition: 'all 0.2s'
                                            }}
                                        >
                                            {c}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* ÔöÇÔöÇ Transaction List ÔöÇÔöÇ */}
                            {entriesWithBalance.length === 0 ? (
                                <div className="empty-state card" style={{ padding: 40 }}>
                                    <FileSpreadsheet size={40} />
                                    <p>No entries found.</p>
                                </div>
                            ) : (
                                <div className="card" style={{ padding: 0, border: '1px solid var(--border-color)', borderRadius: '12px', overflow: 'hidden' }}>
                                    <div className="table-wrapper">
                                        <table className="data-table" style={{ fontSize: 13, borderCollapse: 'collapse' }}>
                                            <thead>
                                                <tr style={{ background: 'var(--bg-main)' }}>
                                                    <th style={{ width: 40, padding: '14px 12px' }}>#</th>
                                                    <th style={{ width: 100 }}>Date</th>
                                                    <th>Particular</th>
                                                    <th style={{ width: 70 }}>Currency</th>
                                                    <th style={{ textAlign: 'right', color: cfg.debitColor, width: 120 }}>ÔêÆ {cfg.credit.split(' ').pop()}</th>
                                                    <th style={{ textAlign: 'right', color: cfg.creditColor, width: 120 }}>+ {cfg.debit.split(' ').pop()}</th>
                                                    <th style={{ textAlign: 'right', width: 130 }}>Balance</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                {entriesWithBalance.map((r, i) => {
                                                    const balCol = r.runningBalance >= 0 ? cfg.balanceColor : 'var(--status-failed)';
                                                    const curCol = { SAR: '#4a9eff', AED: 'var(--brand-gold)', INR: '#a78bfa' }[r.currency] || 'var(--text-muted)';
                                                    return (
                                                        <tr key={r._id + i} style={{ borderBottom: '1px solid var(--border-color)' }}>
                                                            <td style={{ color: 'var(--text-muted)', fontSize: 11, padding: '12px' }}>
                                                                {entriesWithBalance.length - i}
                                                            </td>
                                                            <td style={{ color: 'var(--text-muted)', fontSize: 12, whiteSpace: 'nowrap' }}>
                                                                {r._date ? format(new Date(r._date), 'dd MMM yy') : 'ÔÇö'}
                                                            </td>
                                                            <td style={{ fontWeight: 500, maxWidth: 280 }}>
                                                                <div style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{r.particular}</div>
                                                                {r.reference_type && (
                                                                    <div style={{ fontSize: 10, color: 'var(--text-muted)', fontWeight: 400 }}>
                                                                        {r.reference_type.toUpperCase()}
                                                                    </div>
                                                                )}
                                                            </td>
                                                            <td>
                                                                <span style={{
                                                                    fontSize: 11, fontWeight: 700, padding: '2px 6px', borderRadius: 4,
                                                                    background: `${curCol}15`, color: curCol
                                                                }}>{r.currency}</span>
                                                            </td>
                                                            {/* credit = money going out (paid/distributed) ÔåÆ negative sign */}
                                                            <td style={{ textAlign: 'right', fontWeight: 600, color: r.credit > 0 ? cfg.creditColor : 'var(--text-muted)' }}>
                                                                {r.credit > 0 ? `ÔêÆ${fmt(r.credit)}` : 'ÔÇö'}
                                                            </td>
                                                            {/* debit = money received (deposited/total) ÔåÆ positive sign */}
                                                            <td style={{ textAlign: 'right', fontWeight: 600, color: r.debit > 0 ? cfg.debitColor : 'var(--text-muted)' }}>
                                                                {r.debit > 0 ? `+${fmt(r.debit)}` : 'ÔÇö'}
                                                            </td>
                                                            <td style={{ textAlign: 'right', fontWeight: 700, color: balCol }}>
                                                                {r.runningBalance >= 0 ? '+' : 'ÔêÆ'}{fmt(Math.abs(r.runningBalance))} <span style={{ fontSize: 10, color: 'var(--text-muted)' }}>{r.currency}</span>
                                                            </td>
                                                        </tr>
                                                    );
                                                })}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>
        </div>
    );
}

import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import {
    LayoutDashboard, ArrowLeftRight, Users, UserCog,
    TrendingDown, LogOut, Wallet, RefreshCw, FileSpreadsheet, Settings, X, Activity, Database
} from 'lucide-react';

const NAV = {
    admin: [
        { label: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
        { label: 'Transactions', path: '/transactions', icon: ArrowLeftRight },
        { label: 'Conversion Agents', path: '/conversion-agents', icon: RefreshCw },
        { label: 'Agents', path: '/agents', icon: Users },
        { label: 'Distributors', path: '/distributors', icon: UserCog },
        { label: 'Income & Ops', path: '/expenses', icon: TrendingDown },
        { label: 'Activity Logs', path: '/activity-logs', icon: Activity },
        { label: 'Ledger', path: '/reports', icon: FileSpreadsheet },
        { label: 'Reconciliation', path: '/reconciliation', icon: Database },
        { label: 'Settings', path: '/settings', icon: Settings },
    ],
    collector: [
        { label: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
        { label: 'Transactions', path: '/transactions', icon: ArrowLeftRight },
        { label: 'Conversion Agents', path: '/conversion-agents', icon: RefreshCw },
        { label: 'Agents', path: '/agents', icon: Users },
        { label: 'Distributors', path: '/distributors', icon: UserCog },
        { label: 'Income & Ops', path: '/expenses', icon: TrendingDown },
        { label: 'Activity Logs', path: '/activity-logs', icon: Activity },
        { label: 'Ledger', path: '/reports', icon: FileSpreadsheet },
    ],
};

const ROLE_COLOR = {
    admin: '#f5a623',
    collector: '#4a9eff',
};

export default function Sidebar({ isOpen, onClose }) {
    const { user, role, logout } = useAuth();
    const navigate = useNavigate();
    const links = NAV[role] || NAV.admin;

    const handleLogout = async () => {
        await logout();
        navigate('/login');
    };

    return (
        <aside className={`sidebar ${isOpen ? 'sidebar-open' : ''}`}>
            {/* ÔöÇÔöÇ Brand ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            <div className="sidebar-logo">
                <div className="logo-mark">
                    <div className="logo-icon">
                        <Wallet size={20} />
                    </div>
                    <div className="logo-text">
                        <span className="logo-name">MoneyFlow</span>
                        <span className="logo-sub">ERP System</span>
                    </div>
                </div>
                <button className="sidebar-close-btn" onClick={onClose} aria-label="Close menu">
                    <X size={20} />
                </button>
            </div>

            {/* ÔöÇÔöÇ Nav ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            <nav className="sidebar-nav">
                <div className="nav-section-title">Main Menu</div>
                {links.map(({ label, path, icon: Icon }) => (
                    <NavLink
                        key={path}
                        to={path}
                        className={({ isActive }) => `nav-item${isActive ? ' active' : ''}`}
                        onClick={onClose}
                    >
                        <Icon size={17} className="nav-icon" />
                        <span>{label}</span>
                    </NavLink>
                ))}
            </nav>

            {/* ÔöÇÔöÇ Footer ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            <div className="sidebar-footer">
                <div className="sidebar-user">
                    <div className="user-avatar">
                        {user?.name?.[0]?.toUpperCase() || 'U'}
                    </div>
                    <div className="user-info">
                        <div className="user-name">
                            {user?.name || user?.email?.split('@')[0]}
                        </div>
                        <div className="user-role" style={{ color: ROLE_COLOR[role] }}>
                            {role?.charAt(0).toUpperCase() + role?.slice(1)}
                        </div>
                    </div>
                    <button id="logout-btn" className="logout-btn" onClick={handleLogout} title="Logout">
                        <LogOut size={17} />
                    </button>
                </div>
            </div>
        </aside>
    );
}

import { createContext, useContext, useEffect, useState } from 'react';
import { authService } from '../lib/appwrite';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [role, setRole] = useState(null); // 'admin' | 'collector'
    const [loading, setLoading] = useState(true);

    const detectRole = (email) => {
        if (!email) return null;
        if (email.includes('admin')) return 'admin';
        if (email.includes('collector')) return 'collector';
        return 'admin'; // fallback
    };

    useEffect(() => {
        authService.getCurrentUser().then((u) => {
            setUser(u);
            setRole(detectRole(u?.email));
            setLoading(false);
        });
    }, []);

    const login = async (email, password) => {
        await authService.login(email, password);
        const u = await authService.getCurrentUser();
        setUser(u);
        setRole(detectRole(u?.email));
        return u;
    };

    const logout = async () => {
        await authService.logout();
        setUser(null);
        setRole(null);
    };

    return (
        <AuthContext.Provider value={{ user, role, loading, login, logout }}>
            {children}
        </AuthContext.Provider>
    );
}

export const useAuth = () => useContext(AuthContext);

import { useState, useEffect } from 'react';
import { authService, dbService, Query } from '../lib/appwrite';
import { ledgerService } from '../lib/ledgerService';
import LedgerModal from '../components/LedgerModal';
import Layout from '../components/Layout';
import toast from 'react-hot-toast';
import {
    Plus, X, Pencil, Trash2, RefreshCw, List
} from 'lucide-react';
import { SearchInput } from '../components/filters';


const EMPTY = { name: '', phone: '', notes: '', type: 'conversion_sar', currency: 'AED', sar_balance: 0, aed_balance: 0 };

export default function ConversionAgentsPage() {
    const [agents, setAgents] = useState([]);
    const [convRecs, setConvRecs] = useState([]);   // AED conversion records
    const [loading, setLoading] = useState(true);
    const [modal, setModal] = useState(false);
    const [viewingAgent, setViewingAgent] = useState(null);
    const [editItem, setEditItem] = useState(null);
    const [form, setForm] = useState(EMPTY);
    const [saving, setSaving] = useState(false);
    const [activeTab, setActiveTab] = useState('conversion_sar');

    // Deposit / Receive State
    const [depositModal, setDepositModal] = useState(false);
    const [receiveModal, setReceiveModal] = useState(false);
    const [activeAgent, setActiveAgent] = useState(null);
    const [actionAmount, setActionAmount] = useState('');
    const [actionRate, setActionRate] = useState('');
    const [depositNote, setDepositNote] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [user, setUser] = useState(null);


    const fetchAll = async () => {
        setLoading(true);
        try {
            const [ar, cr] = await Promise.all([
                dbService.listAgents([Query.or([Query.equal('type', 'conversion_sar'), Query.equal('type', 'conversion_aed'), Query.equal('type', 'conversion')])]),
                dbService.listAedConversions(),
            ]);
            setAgents(ar.documents);
            setConvRecs(cr.documents);
        } catch (e) { toast.error(e.message); }
        finally { setLoading(false); }
    };
    useEffect(() => {
        fetchAll();
        authService.getCurrentUser().then(setUser);
    }, []);


    const openNew = () => { setEditItem(null); setForm(EMPTY); setModal(true); };
    const openEdit = (a) => {
        setEditItem(a);
        setForm({
            name: a.name || '',
            phone: a.phone || '',
            notes: a.notes || '',
            type: a.type || 'conversion_sar',
            currency: 'AED',
            sar_balance: a.sar_balance || 0,
            aed_balance: a.aed_balance || 0
        });
        setModal(true);
    };
    const openDeposit = (a) => {
        setActiveAgent(a);
        setActionAmount('');
        setActionRate('');
        setDepositNote('');
        setDepositModal(true);
    };

    const handleSave = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            if (editItem) {
                await dbService.updateAgent(editItem.$id, form);
                toast.success('Updated');
                // Optimistic: update in state
                setAgents(prev => prev.map(a => a.$id === editItem.$id ? { ...a, ...form } : a));
            } else {
                const created = await dbService.createAgent(form);
                toast.success('Conversion agent added');
                // Optimistic: prepend new agent
                setAgents(prev => [{ ...created, ...form }, ...prev]);
            }
            setModal(false);
        } catch (e) { toast.error(e.message); }
        finally { setSaving(false); }
    };

    const handleDelete = async (agent) => {
        const agentRecs = convRecs.filter(r => r.conversion_agent_id === agent.$id);
        const msg = agentRecs.length > 0
            ? `Delete "${agent.name}"? This will also delete ${agentRecs.length} conversion record(s) from the dashboard. This cannot be undone.`
            : `Delete conversion agent "${agent.name}"?`;
        if (!window.confirm(msg)) return;
        try {
            // Delete all AED conversion records for this agent first
            await Promise.all(agentRecs.map(r => dbService.deleteAedConversion(r.$id)));
            await dbService.deleteAgent(agent.$id);
            toast.success(`Deleted agent + ${agentRecs.length} conversion record(s)`);
            // Optimistic: remove from state
            setAgents(prev => prev.filter(a => a.$id !== agent.$id));
            setConvRecs(prev => prev.filter(r => r.conversion_agent_id !== agent.$id));
        } catch (e) { toast.error(e.message); }
    };

    const handleDepositSubmit = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            const amtIn = Number(actionAmount);
            if (!amtIn) throw new Error('Enter valid amount');

            const balCur = activeAgent.type === 'conversion_sar' ? 'SAR' : 'AED';
            
            // 1. Create expense for dashboard
            const expensePayload = {
                title: `Deposit to Conv. Agent ÔÇö ${activeAgent.name}`,
                type: 'expense',
                category: 'Conversion Deposit',
                amount: amtIn,
                currency: balCur,
                date: new Date().toISOString().split('T')[0],
                notes: depositNote || `Deposited ${amtIn} ${balCur}.`,
                distributor_id: activeAgent.$id,
                distributor_name: activeAgent.name
            };
            const createdExpense = await dbService.createExpense(expensePayload);

            // 2. Record Ledger entry (updates agent balance)
            await ledgerService.recordEntry({
                agent: activeAgent,
                amount: amtIn,
                currency: balCur,
                type: 'debit', // Agent received money from us
                reference_type: 'expense',
                reference_id: createdExpense.$id,
                description: `Deposit to conversion agent: ${activeAgent.name}`
            });

            toast.success(`Deposited ${amtIn} ${balCur}`);
            setDepositModal(false);
            fetchAll();
        } catch (err) {
            toast.error(err.message);
        } finally {
            setSaving(false);
        }
    };

    const handleReceiveSubmit = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            const amtSource = Number(actionAmount);
            const rate = Number(actionRate);
            if (!amtSource || !rate) throw new Error('Enter valid amount and rate');

            let incomeCur = '';
            let targetAmt = 0;
            const balCur = activeAgent.type === 'conversion_sar' ? 'SAR' : 'AED';

            if (activeAgent.type === 'conversion_sar') {
                incomeCur = 'AED';
                targetAmt = amtSource / rate;
            } else {
                incomeCur = 'INR';
                targetAmt = amtSource * rate;
            }

            // 1. Create income expense for dashboard
            const expensePayload = {
                title: `Receipt from Conv. Agent ÔÇö ${activeAgent.name}`,
                type: 'income',
                category: 'Conversion Receipt',
                amount: targetAmt,
                currency: incomeCur,
                date: new Date().toISOString().split('T')[0],
                notes: `Received ${(targetAmt || 0).toLocaleString()} ${incomeCur} (Sourced from ${(amtSource || 0).toLocaleString()} ${balCur} @ ${rate}) from conversion agent`,
                distributor_id: activeAgent.$id,
                distributor_name: activeAgent.name
            };
            const createdExpense = await dbService.createExpense(expensePayload);

            // 2. Record Ledger entry (updates agent balance)
            await ledgerService.recordEntry({
                agent: activeAgent,
                amount: amtSource,
                currency: balCur,
                type: 'credit', // Agent gave us money back
                reference_type: 'expense',
                reference_id: createdExpense.$id,
                description: `Receipt from conversion agent: ${activeAgent.name}`
            });

            toast.success(`Received ${(targetAmt || 0).toLocaleString()} ${incomeCur}`);
            setReceiveModal(false);
            fetchAll();
        } catch (err) {
            toast.error(err.message);
        } finally {
            setSaving(false);
        }
}
    return (
        <Layout title="Conversion Agents">
            <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 4 }}>
                    These agents convert <strong>SAR ÔåÆ AED</strong> or <strong>AED ÔåÆ INR</strong> for us. Select one when recording a conversion on the Dashboard.
                </div>
            </div>

            <div className="flex items-center justify-between mb-6 gap-4 flex-wrap">
                <div className="flex items-center gap-4 flex-1">
                    <div style={{ color: 'var(--text-muted)', fontSize: 13 }}>
                        {agents.length} agent{agents.length !== 1 ? 's' : ''}
                    </div>
                    <SearchInput
                        value={searchTerm}
                        onChange={setSearchTerm}
                        placeholder="Search conversion agents..."
                        style={{ maxWidth: '300px' }}
                    />
                </div>
                <button id="new-conv-agent-btn" className="btn btn-accent" onClick={openNew}>
                    <Plus size={16} /> Add Conversion Agent
                </button>
            </div>

            {loading ? (
                <div className="loading-screen" style={{ minHeight: '40vh' }}><div className="spinner" /><p>LoadingÔÇª</p></div>
            ) : agents.length === 0 ? (
                <div className="empty-state card">
                    <RefreshCw size={40} />
                    <p>No conversion agents yet. Add one to get started.</p>
                </div>
            ) : (
                <div className="card">
                    <div className="card-header" style={{ paddingBottom: 16, borderBottom: '1px solid var(--border-color)', display: 'flex', justifyContent: 'center' }}>
                        <div className="flex gap-4">
                            <button
                                style={{
                                    fontSize: 18,
                                    padding: '10px 28px',
                                    borderRadius: '12px',
                                    border: activeTab === 'conversion_sar' ? '1px solid var(--brand-accent)' : '1px solid var(--border-color)',
                                    background: activeTab === 'conversion_sar' ? 'var(--brand-accent)' : 'rgba(255,255,255,0.05)',
                                    color: '#fff',
                                    fontWeight: 700,
                                    cursor: 'pointer',
                                    transition: 'all 0.2s'
                                }}
                                onClick={() => setActiveTab('conversion_sar')}
                            >
                                SAR ÔåÆ AED Agents
                            </button>
                            <button
                                style={{
                                    fontSize: 18,
                                    padding: '10px 28px',
                                    borderRadius: '12px',
                                    border: activeTab === 'conversion_aed' ? '1px solid var(--brand-accent)' : '1px solid var(--border-color)',
                                    background: activeTab === 'conversion_aed' ? 'var(--brand-accent)' : 'rgba(255,255,255,0.05)',
                                    color: '#fff',
                                    fontWeight: 700,
                                    cursor: 'pointer',
                                    transition: 'all 0.2s'
                                }}
                                onClick={() => setActiveTab('conversion_aed')}
                            >
                                AED ÔåÆ INR Agents
                            </button>
                        </div>
                    </div>
                    <div className="table-wrapper">
                        <table className="data-table">
                            <thead>
                                <tr>
                                    <th style={{ width: 40 }}>#</th>
                                    <th>Agent Name</th>
                                    <th className="hide-md" style={{ width: 140 }}>Phone</th>
                                    <th style={{ textAlign: 'right', width: 150 }}>Balance</th>
                                    <th style={{ textAlign: 'center', width: 180 }} className="hide-sm">Operations</th>
                                    <th style={{ textAlign: 'right', width: 120 }}>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {agents
                                    .filter(a => a.type === activeTab)
                                    .filter(a => 
                                        a.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
                                        a.phone?.toLowerCase().includes(searchTerm.toLowerCase())
                                    )
                                    .map((a, i) => {
                                    const bal = activeTab === 'conversion_sar' ? (a.sar_balance || 0) : (a.aed_balance || 0);
                                    const balCur = activeTab === 'conversion_sar' ? 'SAR' : 'AED';

                                    return (
                                        <tr key={a.$id}>
                                            <td style={{ color: 'var(--text-muted)' }}>{i + 1}</td>
                                            <td>
                                                <div style={{ fontWeight: 600 }}>
                                                    <button
                                                        onClick={() => setViewingAgent(a)}
                                                        style={{
                                                            background: 'none', border: 'none', padding: 0,
                                                            fontWeight: 'inherit', cursor: 'pointer',
                                                            textDecoration: 'underline', color: 'var(--brand-accent)'
                                                        }}
                                                    >
                                                        {a.name}
                                                    </button>
                                                </div>
                                                {a.notes && <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{a.notes}</div>}
                                            </td>
                                            <td style={{ color: 'var(--text-muted)' }}>{a.phone || 'ÔÇö'}</td>
                                            <td style={{ textAlign: 'right', fontWeight: 700, color: 'var(--text-primary)' }}>
                                                {(bal || 0).toLocaleString()} <span style={{ fontSize: 11 }}>{balCur}</span>
                                            </td>
                                            <td style={{ textAlign: 'center' }}>
                                                <div style={{ display: 'flex', gap: 6, justifyContent: 'center' }}>
                                                    <button className="btn btn-danger btn-sm" style={{ padding: '4px 12px', fontSize: 12 }} onClick={() => openDeposit(a)}>Deposit</button>
                                                    <button className="btn btn-accent btn-sm" style={{ padding: '4px 12px', fontSize: 12 }} onClick={() => { setActiveAgent(a); setActionAmount(''); setActionRate(''); setReceiveModal(true); }}>Receive</button>
                                                </div>
                                            </td>
                                            <td>
                                                <div style={{ display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                                                    <button className="btn btn-outline btn-sm btn-icon" title="View History" onClick={() => setViewingAgent(a)}><List size={13} /></button>
                                                    <button className="btn btn-outline btn-sm btn-icon" onClick={() => openEdit(a)}><Pencil size={13} /></button>
                                                    <button className="btn btn-danger btn-sm btn-icon" onClick={() => handleDelete(a)}><Trash2 size={13} /></button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                            <tfoot>
                                <tr>
                                    <td colSpan={3} style={{ textAlign: 'right', fontWeight: 700, color: 'var(--text-secondary)' }}>GRAND TOTAL</td>
                                    <td style={{ textAlign: 'right', fontWeight: 800, color: 'var(--brand-accent)' }}>
                                        {(agents.filter(a => a.type === activeTab).reduce((sum, a) => sum + (activeTab === 'conversion_sar' ? (a.sar_balance || 0) : (a.aed_balance || 0)), 0) || 0).toLocaleString()} <span style={{ fontSize: 11 }}>{activeTab === 'conversion_sar' ? 'SAR' : 'AED'}</span>
                                    </td>
                                    <td colSpan={2}></td>
                                </tr>
                            </tfoot>
                        </table>
                    </div>
                </div>
            )}

            {/* History Modal */}
            {viewingAgent && (
                <LedgerModal
                    agent={viewingAgent}
                    onClose={() => setViewingAgent(null)}
                />
            )}

            {/* Modal */}
            {modal && (
                <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setModal(false)}>
                    <div className="modal">
                        <div className="modal-header">
                            <h3 className="modal-title">{editItem ? 'Edit Conversion Agent' : 'Add Conversion Agent'}</h3>
                            <button className="close-btn" onClick={() => setModal(false)}><X size={20} /></button>
                        </div>
                        <form onSubmit={handleSave}>
                            <div className="modal-body">
                                <div className="form-group">
                                    <label className="form-label">Conversion Type *</label>
                                    <div style={{ display: 'flex', gap: 10 }}>
                                        {CONV_TYPES.map(ct => (
                                            <label key={ct.value} style={{
                                                flex: 1, display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px',
                                                border: `2px solid ${form.type === ct.value ? ct.color : 'var(--border-color)'}`,
                                                borderRadius: 10, cursor: 'pointer',
                                                background: form.type === ct.value ? ct.bg : 'transparent',
                                                transition: 'all 0.15s'
                                            }}>
                                                <input type="radio" name="conv_type" value={ct.value}
                                                    checked={form.type === ct.value}
                                                    onChange={() => setForm({ ...form, type: ct.value })}
                                                    style={{ accentColor: ct.color }} />
                                                <span style={{ fontWeight: 700, color: ct.color, fontSize: 14 }}>{ct.label}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                                <div className="form-group">
                                    <label className="form-label">Full Name *</label>
                                    <input id="ca-name" className="form-input" placeholder="Agent name"
                                        value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} required />
                                </div>
                                <div className="form-row" style={{ display: 'flex', gap: 12 }}>
                                    <div className="form-group" style={{ flex: 1 }}>
                                        <label className="form-label">Phone</label>
                                        <input id="ca-phone" className="form-input" placeholder="+966 5X XXX XXXX"
                                            value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} />
                                    </div>
                                    {(user?.role === 'admin' || user?.role === 'collector') && (
                                        <div className="form-group" style={{ flex: 1 }}>
                                            <label className="form-label">
                                                Balance ({form.type === 'conversion_sar' ? 'SAR' : 'AED'})
                                            </label>
                                            <input
                                                className="form-input"
                                                type="number"
                                                step="any"
                                                value={form.type === 'conversion_sar' ? form.sar_balance : form.aed_balance}
                                                onChange={e => {
                                                    const val = parseFloat(e.target.value) || 0;
                                                    if (form.type === 'conversion_sar') setForm({ ...form, sar_balance: val });
                                                    else setForm({ ...form, aed_balance: val });
                                                }}
                                                style={{ border: '1px solid var(--brand-accent)', background: 'rgba(0,255,150,0.05)' }}
                                            />
                                        </div>
                                    )}
                                </div>
                                <div className="form-group">
                                    <label className="form-label">Notes</label>
                                    <textarea id="ca-notes" className="form-textarea" placeholder="Additional infoÔÇª"
                                        value={form.notes} onChange={e => setForm({ ...form, notes: e.target.value })} />
                                </div>
                            </div>
                            <div className="modal-footer">
                                <button type="button" className="btn btn-outline" onClick={() => setModal(false)}>Cancel</button>
                                <button id="save-ca-btn" type="submit" className="btn btn-accent" disabled={saving}>
                                    {saving ? 'SavingÔÇª' : editItem ? 'Update' : 'Add Agent'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Deposit Modal */}
            {depositModal && activeAgent && (() => {
                const balCur = activeAgent.type === 'conversion_sar' ? 'SAR' : 'AED';
                return (
                    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setDepositModal(false)}>
                        <div className="modal-content" style={{ maxWidth: 400, background: 'var(--bg-card)', borderRadius: 16, border: '1px solid rgba(255,255,255,0.05)' }}>
                            <div className="modal-header" style={{ padding: '20px 24px', borderBottom: '1px solid var(--border-color)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <h3 className="modal-title" style={{ fontSize: 18, fontWeight: 700, margin: 0 }}>Deposit to {activeAgent.name}</h3>
                                <button className="close-btn" style={{ background: 'transparent', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' }} onClick={() => setDepositModal(false)}><X size={20} /></button>
                            </div>
                            <form style={{ padding: 24, display: 'flex', flexDirection: 'column', gap: 16 }} onSubmit={handleDepositSubmit}>
                                <div style={{ padding: 12, background: 'rgba(0,0,0,0.2)', borderRadius: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>Current Debt (Balance):</span>
                                    <span style={{ fontSize: 15, fontWeight: 700, color: activeAgent.type === 'conversion_sar' ? '#4a9eff' : 'var(--brand-gold)' }}>
                                        {activeAgent.type === 'conversion_sar' ? `${(Number(activeAgent.sar_balance) || 0).toLocaleString()} SAR` : `${(Number(activeAgent.aed_balance) || 0).toLocaleString()} AED`}
                                    </span>
                                </div>
                                <div className="form-group">
                                    <label className="form-label" style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)', marginBottom: 6, display: 'block' }}>Deposit Amount ({balCur})</label>
                                    <input className="form-input" style={{ width: '100%', padding: '10px 14px', borderRadius: 8, border: '1px solid var(--border-color)', background: 'rgba(255,255,255,0.02)', color: '#fff' }} type="number" step="any" required
                                        value={actionAmount} onChange={e => setActionAmount(e.target.value)} />
                                </div>
                                <div className="form-group">
                                    <label className="form-label" style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)', marginBottom: 6, display: 'block' }}>Notes</label>
                                    <textarea className="form-textarea" style={{ width: '100%', padding: '10px 14px', borderRadius: 8, border: '1px solid var(--border-color)', background: 'rgba(255,255,255,0.02)', color: '#fff' }} rows="3" placeholder="Additional details..."
                                        value={depositNote} onChange={e => setDepositNote(e.target.value)} />
                                </div>
                                <div className="modal-actions" style={{ marginTop: 8, display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
                                    <button type="button" className="btn btn-outline" style={{ padding: '8px 16px', borderRadius: 8 }} onClick={() => setDepositModal(false)}>Cancel</button>
                                    <button type="submit" className="btn btn-accent" style={{ padding: '8px 16px', borderRadius: 8 }} disabled={saving}>
                                        {saving ? 'Processing...' : 'Confirm Deposit'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>
                );
            })()}

            {/* Receive Modal */}
            {receiveModal && activeAgent && (
                <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setReceiveModal(false)}>
                    <div className="modal-content" style={{ maxWidth: 400, background: 'var(--bg-card)', borderRadius: 16, border: '1px solid rgba(255,255,255,0.05)' }}>
                        <div className="modal-header" style={{ padding: '20px 24px', borderBottom: '1px solid var(--border-color)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h3 className="modal-title" style={{ fontSize: 18, fontWeight: 700, margin: 0 }}>Receive from {activeAgent.name}</h3>
                            <button className="close-btn" style={{ background: 'transparent', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' }} onClick={() => setReceiveModal(false)}><X size={20} /></button>
                        </div>
                        <form style={{ padding: 24, display: 'flex', flexDirection: 'column', gap: 16 }} onSubmit={handleReceiveSubmit}>
                            <p style={{ fontSize: 13, color: 'var(--text-muted)', margin: 0 }}>
                                Specify how much <b>{activeAgent.type === 'conversion_sar' ? 'SAR' : 'AED'}</b> is being cleared
                                and at what rate. The resulting {activeAgent.type === 'conversion_sar' ? 'AED' : 'INR'} will be credited to our dashboard balance.
                            </p>
                            <div style={{ padding: 12, background: 'rgba(0,0,0,0.2)', borderRadius: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>Currently Owed:</span>
                                <span style={{ fontSize: 15, fontWeight: 700, color: activeAgent.type === 'conversion_sar' ? '#4a9eff' : 'var(--brand-gold)' }}>
                                    {activeAgent.type === 'conversion_sar' ? `${(Number(activeAgent.sar_balance) || 0).toLocaleString()} SAR` : `${(Number(activeAgent.aed_balance) || 0).toLocaleString()} AED`}
                                </span>
                            </div>
                            <div className="form-group">
                                <label className="form-label" style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)', marginBottom: 6, display: 'block' }}>Source Amount Settled ({activeAgent.type === 'conversion_sar' ? 'SAR' : 'AED'})</label>
                                <input className="form-input" style={{ width: '100%', padding: '10px 14px', borderRadius: 8, border: '1px solid var(--border-color)', background: 'rgba(255,255,255,0.02)', color: '#fff' }} type="number" step="any" required
                                    value={actionAmount} onChange={e => setActionAmount(e.target.value)} />
                            </div>
                            <div className="form-group">
                                <label className="form-label" style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-secondary)', marginBottom: 6, display: 'block' }}>Exchange Rate</label>
                                <input className="form-input" style={{ width: '100%', padding: '10px 14px', borderRadius: 8, border: '1px solid var(--border-color)', background: 'rgba(255,255,255,0.02)', color: '#fff' }} type="number" step="any" required
                                    value={actionRate} onChange={e => setActionRate(e.target.value)} />
                            </div>
                            {actionAmount && actionRate && (
                                <div style={{ marginTop: 8, padding: 12, background: 'rgba(74,158,255,0.1)', borderRadius: 8, fontSize: 14, color: '#4a9eff', fontWeight: 600 }}>
                                    Result: {activeAgent.type === 'conversion_sar' ? (Number(actionAmount) / Number(actionRate)).toLocaleString(undefined, { maximumFractionDigits: 2 }) : (Number(actionAmount) * Number(actionRate) || 0).toLocaleString()} {activeAgent.type === 'conversion_sar' ? 'AED' : 'INR'} will be recorded as income.
                                </div>
                            )}
                            <div className="modal-actions" style={{ marginTop: 8, display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
                                <button type="button" className="btn btn-outline" style={{ padding: '8px 16px', borderRadius: 8 }} onClick={() => setReceiveModal(false)}>Cancel</button>
                                <button type="submit" className="btn btn-accent" style={{ padding: '8px 16px', borderRadius: 8 }} disabled={saving}>
                                    {saving ? 'Processing...' : 'Confirm Receipt'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </Layout >
    );
}

import React, { useState, useEffect } from 'react';
import Layout from '../components/Layout';
import { dbService, authService } from '../lib/appwrite';
import { ledgerService } from '../lib/ledgerService';
import { RefreshCw, CheckCircle, AlertTriangle, Play, Database, Trash2 } from 'lucide-react';
import toast from 'react-hot-toast';

export default function ReconciliationPage() {
    const [loading, setLoading] = useState(false);
    const [stats, setStats] = useState({
        ledgerCount: 0,
        transactionCount: 0,
        expenseCount: 0,
        bulkConversionCount: 0,
        agentCount: 0
    });
    const [logs, setLogs] = useState([]);
    const [user, setUser] = useState(null);

    useEffect(() => {
        const init = async () => {
            const u = await authService.getCurrentUser();
            setUser(u);
            loadStats();
        };
        init();
    }, []);

    const loadStats = async () => {
        setLoading(true);
        try {
            const [ledger, txs, exps, bulks, agts] = await Promise.all([
                dbService.listLedgerEntries(),
                dbService.listTransactions(),
                dbService.listExpenses(),
                dbService.listAedConversions(),
                dbService.listAgents()
            ]);

            setStats({
                ledgerCount: ledger.total,
                transactionCount: txs.total,
                expenseCount: exps.total,
                bulkConversionCount: bulks.total,
                agentCount: agts.total
            });
        } catch (err) {
            console.error('Failed to load stats:', err);
            addLog('Error loading stats: ' + err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const addLog = (msg, type = 'info') => {
        setLogs(prev => [{ msg, type, time: new Date().toLocaleTimeString() }, ...prev].slice(0, 100));
    };

    const handleClearLedger = async () => {
        if (!window.confirm('WARNING: This will delete ALL existing ledger entries. Are you sure?')) return;

        setLoading(true);
        addLog('Clearing all ledger entries...', 'warning');
        try {
            const entries = await dbService.listLedgerEntries();
            for (const entry of entries.documents) {
                await dbService.deleteLedgerEntry(entry.$id);
            }
            addLog(`Deleted ${entries.total} entries.`, 'success');
            loadStats();
        } catch (err) {
            addLog('Clear failed: ' + err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleWipeAndFullRebuild = async () => {
        if (!window.confirm('ÔÜá´©Å WIPE & FULL REBUILD:\n\n1. Delete ALL ledger entries\n2. Reset all agent balances to 0\n3. Rebuild everything with correct agent_type\n\nThis cannot be undone. Continue?')) return;

        setLoading(true);
        addLog('=== WIPE & FULL REBUILD STARTED ===', 'warning');

        try {
            // Step 1: Clear all ledger entries
            addLog('Step 1/3: Clearing all ledger entries...', 'warning');
            const entries = await dbService.listLedgerEntries();
            let deleted = 0;
            for (const entry of entries.documents) {
                try {
                    await dbService.deleteLedgerEntry(entry.$id);
                    deleted++;
                    if (deleted % 50 === 0) addLog(`Deleted ${deleted} entries...`, 'info');
                } catch (e) {
                    // ignore
                }
            }
            addLog(`Deleted ${deleted} ledger entries.`, 'success');

            // Step 2: Reset all agent balances to 0
            addLog('Step 2/3: Resetting all agent balances to 0...', 'warning');
            const [agts] = await Promise.all([dbService.listAgents()]);
            let resetCount = 0;
            for (const agent of agts.documents) {
                await dbService.updateAgent(agent.$id, {
                    sar_balance: 0,
                    aed_balance: 0,
                    inr_balance: 0
                });
                resetCount++;
            }
            addLog(`Reset ${resetCount} agent balances to 0.`, 'success');

            // Step 3: Rebuild ledger with correct agent_type
            addLog('Step 3/3: Rebuilding ledger with correct agent_type...', 'warning');
            const [txs, exps, bulks, existingLedger] = await Promise.all([
                dbService.listTransactions(),
                dbService.listExpenses(),
                dbService.listAedConversions(),
                dbService.listLedgerEntries()
            ]);
            const existingRefs = new Set(existingLedger.documents.map(l => l.reference_id));
            let created = 0;

            // Process Transactions
            for (const tx of txs.documents) {
                if (tx.collection_agent_id && !existingRefs.has(tx.$id + '_coll')) {
                    const colAgent = agts.documents.find(a => a.$id === tx.collection_agent_id);
                    await dbService.createLedgerEntry({
                        agent_id: tx.collection_agent_id,
                        agent_name: tx.collection_agent_name,
                        agent_type: colAgent?.type || 'collection',
                        amount: Number(tx.collected_amount),
                        currency: tx.collected_currency || 'SAR',
                        type: 'debit',
                        reference_type: 'transaction',
                        description: `Automated Sync: Collection for transaction #${tx.tx_id || tx.$id.slice(-6)}`,
                        reference_id: tx.$id + '_coll'
                    });
                    created++;
                }
                if (tx.distributor_id && !existingRefs.has(tx.$id + '_dist')) {
                    const distAgent = agts.documents.find(a => a.$id === tx.distributor_id);
                    await dbService.createLedgerEntry({
                        agent_id: tx.distributor_id,
                        agent_name: tx.distributor_name,
                        agent_type: distAgent?.type || 'distributor',
                        amount: Number(tx.actual_inr_distributed || tx.inr_requested),
                        currency: 'INR',
                        type: 'credit',
                        reference_type: 'transaction',
                        description: `Automated Sync: Distribution for transaction #${tx.tx_id || tx.$id.slice(-6)}`,
                        reference_id: tx.$id + '_dist'
                    });
                    created++;
                }
                if (tx.conversion_agent_id && !existingRefs.has(tx.$id + '_conv')) {
                    const convAgent = agts.documents.find(a => a.$id === tx.conversion_agent_id);
                    await dbService.createLedgerEntry({
                        agent_id: tx.conversion_agent_id,
                        agent_name: tx.conversion_agent_name,
                        agent_type: convAgent?.type || 'conversion_sar',
                        amount: Number(tx.collected_amount),
                        currency: tx.collected_currency || 'SAR',
                        type: 'debit',
                        reference_type: 'transaction',
                        description: `Automated Sync: Individual conversion #${tx.tx_id || tx.$id.slice(-6)}`,
                        reference_id: tx.$id + '_conv'
                    });
                    created++;
                }
            }

            // Process Expenses
            for (const exp of exps.documents) {
                if (existingRefs.has(exp.$id)) continue;
                if (!exp.distributor_id && !exp.distributor_name) continue;
                const matchedAgent = agts.documents.find(a => a.$id === exp.distributor_id);
                if (!matchedAgent) continue;

                const targetType = matchedAgent.type;

                if (exp.category === 'Agent Payment') {
                    await dbService.createLedgerEntry({
                        agent_id: matchedAgent.$id, agent_name: matchedAgent.name, agent_type: targetType,
                        amount: Number(exp.amount), currency: exp.currency || 'SAR', type: 'credit',
                        reference_type: 'expense', description: `Automated Sync: Payment record ${exp.notes || ''}`, reference_id: exp.$id
                    });
                    created++;
                } else if (exp.category === 'Distributor Deposit') {
                    await dbService.createLedgerEntry({
                        agent_id: matchedAgent.$id, agent_name: matchedAgent.name, agent_type: targetType,
                        amount: Number(exp.amount), currency: exp.currency || 'INR', type: 'debit',
                        reference_type: 'expense', description: `Automated Sync: Deposit record ${exp.notes || ''}`, reference_id: exp.$id
                    });
                    created++;
                } else if (exp.category === 'Conversion Deposit') {
                    await dbService.createLedgerEntry({
                        agent_id: matchedAgent.$id, agent_name: matchedAgent.name, agent_type: targetType,
                        amount: Number(exp.amount), currency: exp.currency || 'SAR', type: 'debit',
                        reference_type: 'expense', description: `Automated Sync: Conversion Deposit ${exp.notes || ''}`, reference_id: exp.$id
                    });
                    created++;
                } else if (exp.category === 'Conversion Receipt') {
                    const match = exp.notes?.match(/Sourced from ([\d,.]+) /);
                    const clearedAmt = match ? Number(match[1].replace(/,/g, '')) : Number(exp.amount);
                    const clearedCur = exp.notes?.includes('SAR') ? 'SAR' : 'AED';
                    await dbService.createLedgerEntry({
                        agent_id: matchedAgent.$id, agent_name: matchedAgent.name, agent_type: targetType,
                        amount: clearedAmt, currency: clearedCur, type: 'credit',
                        reference_type: 'expense', description: `Automated Sync: Conversion Receipt ${exp.notes || ''}`, reference_id: exp.$id
                    });
                    created++;
                } else if (exp.category === 'AEDÔåÆINR Conversion') {
                    if (exp.currency === 'AED') {
                        await dbService.createLedgerEntry({
                            agent_id: matchedAgent.$id, agent_name: matchedAgent.name, agent_type: targetType,
                            amount: Number(exp.amount), currency: 'AED', type: 'credit',
                            reference_type: 'expense', description: `Automated Sync: AEDÔåÆINR Conversion (AED Side)`, reference_id: exp.$id
                        });
                        created++;
                    } else if (exp.currency === 'INR') {
                        await dbService.createLedgerEntry({
                            agent_id: matchedAgent.$id, agent_name: matchedAgent.name, agent_type: targetType,
                            amount: Number(exp.amount), currency: 'INR', type: 'debit',
                            reference_type: 'expense', description: `Automated Sync: AEDÔåÆINR Conversion (INR Side)`, reference_id: exp.$id
                        });
                        created++;
                    }
                }
            }

            // Process Bulk Conversions
            for (const bulk of bulks.documents) {
                if (!bulk.conversion_agent_id) continue;
                const convAgent = agts.documents.find(a => a.$id === bulk.conversion_agent_id);
                if (!existingRefs.has(bulk.$id + '_src')) {
                    const srcAmt = Number(bulk.sar_amount || bulk.aed_amount);
                    const srcCur = bulk.sar_amount ? 'SAR' : 'AED';
                    await dbService.createLedgerEntry({
                        agent_id: bulk.conversion_agent_id, agent_name: bulk.conversion_agent_name,
                        agent_type: convAgent?.type || 'conversion_sar',
                        amount: srcAmt, currency: srcCur, type: 'debit',
                        reference_type: 'aed_conversion', description: `Automated Sync: Bulk conversion source (${srcCur})`, reference_id: bulk.$id + '_src'
                    });
                    created++;
                }
                if (!existingRefs.has(bulk.$id + '_tgt') && bulk.sar_amount && bulk.aed_amount) {
                    await dbService.createLedgerEntry({
                        agent_id: bulk.conversion_agent_id, agent_name: bulk.conversion_agent_name,
                        agent_type: convAgent?.type || 'conversion_sar',
                        amount: Number(bulk.aed_amount), currency: 'AED', type: 'credit',
                        reference_type: 'aed_conversion', description: `Automated Sync: Bulk conversion target (AED)`, reference_id: bulk.$id + '_tgt'
                    });
                    created++;
                }
            }

            addLog(`=== REBUILD COMPLETE: Created ${created} entries ===`, 'success');
            loadStats();
        } catch (err) {
            addLog('Wipe & Rebuild failed: ' + err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleRebuildLedger = async () => {
        setLoading(true);
        addLog('Starting Ledger Rebuild sync...', 'info');
        
        try {
            // 1. Load everything
            const [txs, exps, bulks, agts, existingLedger] = await Promise.all([
                dbService.listTransactions(),
                dbService.listExpenses(),
                dbService.listAedConversions(),
                dbService.listAgents(),
                dbService.listLedgerEntries()
            ]);

            const existingRefs = new Set(existingLedger.documents.map(l => l.reference_id));
            let createdCount = 0;

            // 2. Process Transactions (Distribution & Collection)
            for (const tx of txs.documents) {
                // Agent Collection (Receiving money from client)
                if (tx.collection_agent_id && !existingRefs.has(tx.$id + '_coll')) {
                    const colAgent = agts.documents.find(a => a.$id === tx.collection_agent_id);
                    await dbService.createLedgerEntry({
                        agent_id: tx.collection_agent_id,
                        agent_name: tx.collection_agent_name,
                        agent_type: colAgent?.type || 'collection',
                        amount: Number(tx.collected_amount),
                        currency: tx.collected_currency || 'SAR',
                        type: 'debit', // Agent received money from client
                        reference_type: 'transaction',
                        description: `Automated Sync: Collection for transaction #${tx.tx_id || tx.$id.slice(-6)}`,
                        reference_id: tx.$id + '_coll'
                    });
                    createdCount++;
                }

                // Distributor Send (Giving INR to client)
                if (tx.distributor_id && !existingRefs.has(tx.$id + '_dist')) {
                    const distAgent = agts.documents.find(a => a.$id === tx.distributor_id);
                    await dbService.createLedgerEntry({
                        agent_id: tx.distributor_id,
                        agent_name: tx.distributor_name,
                        agent_type: distAgent?.type || 'distributor',
                        amount: Number(tx.actual_inr_distributed || tx.inr_requested),
                        currency: 'INR',
                        type: 'credit', // Distributor gave INR to client (reduced balance)
                        reference_type: 'transaction',
                        description: `Automated Sync: Distribution for transaction #${tx.tx_id || tx.$id.slice(-6)}`,
                        reference_id: tx.$id + '_dist'
                    });
                    createdCount++;
                }

                // Conversion Agent logic (SAR -> AED or AED -> INR)
                if (tx.conversion_agent_id && !existingRefs.has(tx.$id + '_conv')) {
                    const convAgent = agts.documents.find(a => a.$id === tx.conversion_agent_id);
                    await dbService.createLedgerEntry({
                        agent_id: tx.conversion_agent_id,
                        agent_name: tx.conversion_agent_name,
                        agent_type: convAgent?.type || 'conversion_sar',
                        amount: Number(tx.collected_amount),
                        currency: tx.collected_currency || 'SAR',
                        type: 'debit', // Agent received SAR to convert
                        reference_type: 'transaction',
                        description: `Automated Sync: Individual conversion #${tx.tx_id || tx.$id.slice(-6)}`,
                        reference_id: tx.$id + '_conv'
                    });
                    createdCount++;
                }
            }

            // 3. Process Expenses (Payments & Deposits)
            for (const exp of exps.documents) {
                if (existingRefs.has(exp.$id)) continue;

                // Match either by ID or Name (for historical compatibility)
                if (exp.distributor_id || exp.distributor_name) {
                    const matchedAgent = agts.documents.find(a =>
                        (exp.distributor_id && a.$id === exp.distributor_id)
                    );

                    if (matchedAgent) {
                        const targetId = matchedAgent.$id;
                        const targetName = matchedAgent.name;
                        const targetType = matchedAgent.type;

                        if (exp.category === 'Agent Payment') {
                            await dbService.createLedgerEntry({
                                agent_id: targetId,
                                agent_name: targetName,
                                agent_type: targetType,
                                amount: Number(exp.amount),
                                currency: exp.currency || 'SAR',
                                type: 'credit', // Agent gave us money
                                reference_type: 'expense',
                                description: `Automated Sync: Payment record ${exp.notes || ''}`,
                                reference_id: exp.$id
                            });
                            createdCount++;
                        } else if (exp.category === 'Distributor Deposit') {
                            await dbService.createLedgerEntry({
                                agent_id: targetId,
                                agent_name: targetName,
                                agent_type: targetType,
                                amount: Number(exp.amount),
                                currency: exp.currency || 'INR',
                                type: 'debit', // Distributor received INR deposit from us
                                reference_type: 'expense',
                                description: `Automated Sync: Deposit record ${exp.notes || ''}`,
                                reference_id: exp.$id
                            });
                            createdCount++;
                        } else if (exp.category === 'Conversion Deposit') {
                            await dbService.createLedgerEntry({
                                agent_id: targetId,
                                agent_name: targetName,
                                agent_type: targetType,
                                amount: Number(exp.amount),
                                currency: exp.currency || 'SAR',
                                type: 'debit', // Conversion agent received money from us
                                reference_type: 'expense',
                                description: `Automated Sync: Conversion Deposit ${exp.notes || ''}`,
                                reference_id: exp.$id
                            });
                            createdCount++;
                        } else if (exp.category === 'Conversion Receipt') {
                            let clearedAmt = 0;
                            const match = exp.notes?.match(/Sourced from ([\d,.]+) /);
                            if (match) clearedAmt = Number(match[1].replace(/,/g, ''));
                            else clearedAmt = Number(exp.amount);

                            const clearedCur = exp.notes?.includes('SAR') ? 'SAR' : 'AED';

                            await dbService.createLedgerEntry({
                                agent_id: targetId,
                                agent_name: targetName,
                                agent_type: targetType,
                                amount: clearedAmt,
                                currency: clearedCur,
                                type: 'credit', // Conversion agent gave us converted money
                                reference_type: 'expense',
                                description: `Automated Sync: Conversion Receipt ${exp.notes || ''}`,
                                reference_id: exp.$id
                            });
                            createdCount++;
                        } else if (exp.category === 'AEDÔåÆINR Conversion') {
                            // Recording the AED side for the agent
                            if (exp.currency === 'AED') {
                                await dbService.createLedgerEntry({
                                    agent_id: targetId,
                                    agent_name: targetName,
                                    agent_type: targetType,
                                    amount: Number(exp.amount),
                                    currency: 'AED',
                                    type: 'credit', // Agent gave us AED
                                    reference_type: 'expense',
                                    description: `Automated Sync: AEDÔåÆINR Conversion (AED Side)`,
                                    reference_id: exp.$id
                                });
                                createdCount++;
                            } else if (exp.currency === 'INR') {
                                // Recording the INR side
                                await dbService.createLedgerEntry({
                                    agent_id: targetId,
                                    agent_name: targetName,
                                    agent_type: targetType,
                                    amount: Number(exp.amount),
                                    currency: 'INR',
                                    type: 'debit', // Agent received INR from client/distributor
                                    reference_type: 'expense',
                                    description: `Automated Sync: AEDÔåÆINR Conversion (INR Side)`,
                                    reference_id: exp.$id
                                });
                                createdCount++;
                            }
                        }
                    }
                }
            }

            // 4. Process Bulk Conversions (Double entry for source and target)
            for (const bulk of bulks.documents) {
                if (!bulk.conversion_agent_id) continue;

                const convAgent = agts.documents.find(a => a.$id === bulk.conversion_agent_id);

                // A. Source Side (Agent receives funds to convert - Debit)
                if (!existingRefs.has(bulk.$id + '_src')) {
                    const srcAmt = Number(bulk.sar_amount || bulk.aed_amount);
                    const srcCur = bulk.sar_amount ? 'SAR' : 'AED';

                    await dbService.createLedgerEntry({
                        agent_id: bulk.conversion_agent_id,
                        agent_name: bulk.conversion_agent_name,
                        agent_type: convAgent?.type || 'conversion_sar',
                        amount: srcAmt,
                        currency: srcCur,
                        type: 'debit', // Agent received funds to convert
                        reference_type: 'aed_conversion',
                        description: `Automated Sync: Bulk conversion source (${srcCur})`,
                        reference_id: bulk.$id + '_src'
                    });
                    createdCount++;
                }

                // B. Target Side (Agent returns converted funds - Credit)
                if (!existingRefs.has(bulk.$id + '_tgt')) {
                    if (bulk.sar_amount && bulk.aed_amount) {
                         // SAR -> AED: Agent gives us AED
                         await dbService.createLedgerEntry({
                            agent_id: bulk.conversion_agent_id,
                            agent_name: bulk.conversion_agent_name,
                            agent_type: convAgent?.type || 'conversion_sar',
                            amount: Number(bulk.aed_amount),
                            currency: 'AED',
                            type: 'credit', // Agent returned converted funds
                            reference_type: 'aed_conversion',
                            description: `Automated Sync: Bulk conversion target (AED)`,
                            reference_id: bulk.$id + '_tgt'
                        });
                        createdCount++;
                    }
                }
            }

            addLog(`Rebuild complete. Created ${createdCount} missing entries.`, 'success');
            loadStats();
        } catch (err) {
            addLog('Rebuild failed: ' + err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    const handleSyncAgentBalances = async () => {
        if (!window.confirm('This will update the "Balance" column for all agents to match their ledger historical total. Proceed?')) return;

        setLoading(true);
        addLog('Syncing agent balances with ledger...', 'info');
        try {
            const [agts, ledger] = await Promise.all([
                dbService.listAgents(),
                dbService.listLedgerEntries()
            ]);

            let updatedCount = 0;
            for (const agent of agts.documents) {
                // Filter entries by agent_id AND agent_type to prevent cross-contamination
                const entries = ledger.documents.filter(l =>
                    l.agent_id === agent.$id &&
                    (!l.agent_type || l.agent_type === agent.type)
                );

                let newSar = 0;
                let newAed = 0;
                let newInr = 0;

                entries.forEach(e => {
                    // Debit adds to balance, Credit subtracts
                    const amt = e.type === 'debit' ? Number(e.amount) : -Number(e.amount);

                    if (e.currency === 'SAR') newSar += amt;
                    if (e.currency === 'AED') newAed += amt;
                    if (e.currency === 'INR') newInr += amt;
                });

                // Round to 2 decimal places
                newSar = Math.round(newSar * 100) / 100;
                newAed = Math.round(newAed * 100) / 100;
                newInr = Math.round(newInr * 100) / 100;

                // Only update if changed
                const curSar = Math.round((agent.sar_balance || 0) * 100) / 100;
                const curAed = Math.round((agent.aed_balance || 0) * 100) / 100;
                const curInr = Math.round((agent.inr_balance || 0) * 100) / 100;

                if (curSar !== newSar || curAed !== newAed || curInr !== newInr) {
                    await dbService.updateAgent(agent.$id, {
                        sar_balance: newSar,
                        aed_balance: newAed,
                        inr_balance: newInr
                    });
                    updatedCount++;
                    addLog(`Synced ${agent.name} (${agent.type}): SAR=${newSar}, AED=${newAed}, INR=${newInr}`, 'info');
                }
            }

            addLog(`Balance sync complete. Updated ${updatedCount} agents.`, 'success');
            loadStats();
        } catch (err) {
            addLog('Sync failed: ' + err.message, 'error');
        } finally {
            setLoading(false);
        }
    };

    if (user?.role !== 'admin') {
        return <Layout title="Access Denied"><div className="card">You do not have permission to access this page.</div></Layout>;
    }

    return (
        <Layout title="System Reconciliation">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="card">
                    <div className="card-header">
                        <Database size={20} className="text-accent" />
                        <h3 style={{ margin: 0 }}>Ledger Health</h3>
                    </div>
                    <div style={{ padding: 20 }}>
                        <div className="flex flex-col gap-4">
                            <div className="flex justify-between items-center p-3 bg-dark-lighter rounded">
                                <span className="text-muted">Total Ledger Entries</span>
                                <span className="font-bold">{stats.ledgerCount}</span>
                            </div>
                            <div className="flex justify-between items-center p-3 bg-dark-lighter rounded">
                                <span className="text-muted">Total Transactions</span>
                                <span className="font-bold">{stats.transactionCount}</span>
                            </div>
                            <div className="flex justify-between items-center p-3 bg-dark-lighter rounded">
                                <span className="text-muted">Total Expenses/Payments</span>
                                <span className="font-bold">{stats.expenseCount}</span>
                            </div>
                            <div className="flex justify-between items-center p-3 bg-dark-lighter rounded">
                                <span className="text-muted">Total Bulk Conversions</span>
                                <span className="font-bold">{stats.bulkConversionCount}</span>
                            </div>
                        </div>

                        <div className="flex flex-col gap-3 mt-6">
                            <button
                                className="btn btn-accent w-full flex items-center justify-center gap-2"
                                onClick={handleRebuildLedger}
                                disabled={loading}
                            >
                                <Play size={16} /> {loading ? 'Processing...' : 'Sync & Rebuild Ledger'}
                            </button>
                            <button
                                className="btn btn-outline w-full flex items-center justify-center gap-2"
                                onClick={handleSyncAgentBalances}
                                disabled={loading}
                            >
                                <RefreshCw size={16} /> Sync Balances (Agents Table)
                            </button>
                            <button
                                className="btn btn-danger w-full flex items-center justify-center gap-2"
                                onClick={handleClearLedger}
                                disabled={loading}
                            >
                                <Trash2 size={16} /> Clear Ledger Only
                            </button>
                            <button
                                className="btn btn-danger w-full flex items-center justify-center gap-2"
                                style={{ background: 'rgba(255,84,112,0.15)', border: '1px solid rgba(255,84,112,0.4)', color: 'var(--status-failed)' }}
                                onClick={handleWipeAndFullRebuild}
                                disabled={loading}
                            >
                                <Database size={16} /> Wipe & Full Rebuild (Reset All)
                            </button>
                        </div>
                    </div>
                </div>

                <div className="card">
                    <div className="card-header">
                        <AlertTriangle size={20} className="text-warning" />
                        <h3 style={{ margin: 0 }}>System Logs</h3>
                    </div>
                    <div style={{ padding: 0, height: '400px', overflowY: 'auto' }}>
                        {logs.length === 0 ? (
                            <div style={{ padding: 20, textAlign: 'center', color: 'var(--text-muted)' }}>
                                No activity yet. Run a tool to see logs.
                            </div>
                        ) : (
                            <div className="flex flex-col">
                                {logs.map((log, i) => (
                                    <div key={i} style={{ 
                                        padding: '10px 16px', 
                                        borderBottom: '1px solid var(--border-color)',
                                        fontSize: '13px',
                                        background: log.type === 'error' ? 'rgba(255,84,112,0.05)' : log.type === 'success' ? 'rgba(0,200,150,0.05)' : 'transparent'
                                    }}>
                                        <span style={{ color: 'var(--text-muted)', marginRight: 8 }}>[{log.time}]</span>
                                        <span style={{ 
                                            color: log.type === 'error' ? 'var(--status-failed)' : log.type === 'success' ? 'var(--brand-accent)' : log.type === 'warning' ? 'var(--brand-gold)' : 'inherit'
                                        }}>
                                            {log.msg}
                                        </span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="card mt-6" style={{ padding: 24, background: 'rgba(255,165,0,0.05)', border: '1px solid rgba(255,165,0,0.2)' }}>
                <h4 className="flex items-center gap-2 text-warning" style={{ marginTop: 0 }}>
                    <AlertTriangle size={18} /> Important Note
                </h4>
                <p className="text-secondary" style={{ fontSize: 14, margin: '8px 0 0' }}>
                    The "Sync & Rebuild" tool will scan all historical transactions and expenses. 
                    It checks if a ledger entry already exists for each event. 
                    If not, it creates a new one. This is safe to run multiple times as it uses "reference_id" to prevent duplicates.
                    Use "Sync Balances" after rebuilding to ensure the main agents list shows the correct totals.
                </p>
            </div>
        </Layout>
    );
}

import { useState, useEffect, useMemo } from 'react';
import { dbService } from '../lib/appwrite';
import Layout from '../components/Layout';
import toast from 'react-hot-toast';
import { Download, FileSpreadsheet, MessageCircle } from 'lucide-react';
import { format } from 'date-fns';
import * as XLSX from 'xlsx';

// Filter components
import { SearchInput, DateRangeFilter, CurrencyFilter, TypeFilter, FilterBar } from '../components/filters';
import { applyDateRange } from '../utils/filterHelpers';

const fmt = (n) => n.toLocaleString('en-IN', { maximumFractionDigits: 2 });

const TYPE_OPTIONS = [
    { value: 'income', label: 'Income', color: 'var(--brand-accent)' },
    { value: 'expense', label: 'Expenses', color: 'var(--status-failed)' }
];

export default function ReportsPage() {
    const [txs, setTxs] = useState([]);
    const [expenses, setExpenses] = useState([]);
    const [aedConversions, setAedConversions] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filter states
    const [dateRange, setDateRange] = useState({ range: 'All Time', customFrom: '', customTo: '' });
    const [search, setSearch] = useState('');
    const [typeFilter, setTypeFilter] = useState(['income', 'expense']);
    const [currencyFilter, setCurrencyFilter] = useState('All');

    const fetchAll = async () => {
        setLoading(true);
        try {
            const [t, ex, ac] = await Promise.all([
                dbService.listTransactions(),
                dbService.listExpenses(),
                dbService.listAedConversions(),
            ]);
            setTxs(t.documents);
            setExpenses(ex.documents);
            setAedConversions(ac.documents);
        } catch (e) {
            toast.error('Failed to load data: ' + e.message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { fetchAll(); }, []);

    // Build unified ledger entries
    const allEntries = useMemo(() => {
        const entries = [];

        // Distribution (Debit in INR) - money leaving the system to customers!
        txs.forEach(tx => {
            if (tx.status === 'completed' && Number(tx.actual_inr_distributed) > 0) {
                entries.push({
                    _type: 'transaction',
                    _date: tx.$updatedAt || tx.$createdAt,
                    _id: tx.$id + '_dist',
                    particular: `${tx.client_name} ÔÇö Distribution`,
                    txId: tx.tx_id || '',
                    currency: 'INR',
                    credit: 0,
                    debit: Number(tx.actual_inr_distributed),
                    agent: tx.distributor_name || '',
                    notes: tx.notes || '',
                });
            }
        });

        if (typeFilter.includes('income')) {
            expenses.filter(e => e.type === 'income').forEach(e => {
                entries.push({
                    _type: 'income',
                    _date: e.$createdAt,
                    _id: e.$id,
                    particular: e.title || 'Income',
                    txId: '',
                    currency: e.currency || 'AED',
                    credit: Number(e.amount) || 0,
                    debit: 0,
                    agent: '',
                    notes: `${e.category || ''}${e.notes ? ' ÔÇö ' + e.notes : ''}`,
                });
            });
        }

        if (typeFilter.includes('expense')) {
            // Exclude internal transfers/deposits to distributors since they are still inside the system
            expenses
                .filter(e => e.type !== 'income' && e.category !== 'Distributor Deposit' && e.category !== 'Distributor Transfer')
                .forEach(e => {
                    entries.push({
                        _type: 'expense',
                        _date: e.$createdAt,
                        _id: e.$id,
                        particular: e.title || 'Expense',
                        txId: '',
                        currency: e.currency || 'AED',
                        credit: 0,
                        debit: Number(e.amount) || 0,
                        agent: '',
                        notes: `${e.category || ''}${e.notes ? ' ÔÇö ' + e.notes : ''}`,
                    });
                });

            // Show SAR -> AED Conversions in the ledger
            aedConversions.forEach(c => {
                // SAR Out (Debit)
                entries.push({
                    _type: 'expense',
                    _date: c.$createdAt || c.date,
                    _id: c.$id + '_sar',
                    particular: `SARÔåÆAED Conversion via ${c.conversion_agent_name || ''}`,
                    txId: '',
                    currency: 'SAR',
                    credit: 0,
                    debit: Number(c.sar_amount) || 0,
                    agent: c.conversion_agent_name || '',
                    notes: `Rate: ${c.sar_rate || ''}`,
                });

                // AED In (Credit)
                entries.push({
                    _type: 'income',
                    _date: c.$createdAt || c.date,
                    _id: c.$id + '_aed',
                    particular: `SARÔåÆAED Conversion via ${c.conversion_agent_name || ''}`,
                    txId: '',
                    currency: 'AED',
                    credit: Number(c.aed_amount) || 0,
                    debit: 0,
                    agent: c.conversion_agent_name || '',
                    notes: `Converted from ${Number(c.sar_amount) || 0} SAR`,
                });
            });
        }

        // Sort by date ascending for ledger
        entries.sort((a, b) => new Date(a._date) - new Date(b._date));
        return entries;
    }, [txs, expenses, aedConversions, typeFilter]);

    // Apply filters
    const filtered = useMemo(() => {
        let result = [...allEntries];

        // Apply date range
        result = applyDateRange(result, dateRange.range, dateRange.customFrom, dateRange.customTo, '_date');

        // Apply currency filter
        if (currencyFilter !== 'All') {
            result = result.filter(r => r.currency === currencyFilter);
        }

        // Apply search filter
        if (search.trim()) {
            const term = search.toLowerCase();
            result = result.filter(r =>
                r.particular?.toLowerCase().includes(term) ||
                r.txId?.toLowerCase().includes(term) ||
                r.agent?.toLowerCase().includes(term) ||
                r.notes?.toLowerCase().includes(term)
            );
        }

        return result;
    }, [allEntries, dateRange, currencyFilter, search]);

    // Ledger totals per currency
    const allCurrencies = ['SAR', 'AED', 'INR'];
    const displayCurrencies = currencyFilter === 'All' ? allCurrencies : [currencyFilter];

    const totals = useMemo(() => {
        const result = {};
        displayCurrencies.forEach(cur => {
            const curEntries = filtered.filter(e => e.currency === cur);
            const totalCredit = curEntries.reduce((a, e) => a + Number(e.credit || 0), 0);
            const totalDebit = curEntries.reduce((a, e) => a + Number(e.debit || 0), 0);
            let bal = totalCredit - totalDebit;
            if (Math.abs(bal) < 0.001) bal = 0;
            result[cur] = { credit: totalCredit, debit: totalDebit, balance: bal };
        });
        return result;
    }, [filtered, displayCurrencies]);

    // Running balance per currency
    const entriesWithBalance = useMemo(() => {
        const runningBal = { SAR: 0, AED: 0, INR: 0 };
        return filtered.map(entry => {
            const cur = entry.currency;
            if (cur && runningBal[cur] !== undefined) {
                runningBal[cur] += Number(entry.credit || 0) - Number(entry.debit || 0);
                if (Math.abs(runningBal[cur]) < 0.001) runningBal[cur] = 0;
            }
            return { ...entry, runningBalance: cur ? runningBal[cur] : 0 };
        });
    }, [filtered]);

    const exportToExcel = () => {
        if (filtered.length === 0) return toast.error('No records to export');
        const rows = filtered.map((r, i) => ({
            '#': i + 1,
            'Date': r._date ? format(new Date(r._date), 'dd-MM-yyyy HH:mm') : '',
            'Particular': r.particular,
            'TX ID': r.txId || '',
            'Type': r._type.charAt(0).toUpperCase() + r._type.slice(1),
            'Currency': r.currency,
            'Credit': r.credit || '',
            'Debit': r.debit || '',
            'Agent': r.agent || '',
            'Notes': r.notes || '',
        }));

        // Add summary rows
        rows.push({});
        rows.push({ '#': '', 'Date': '', 'Particular': 'SUMMARY', 'TX ID': '', 'Type': '', 'Currency': '', 'Credit': '', 'Debit': '' });
        displayCurrencies.forEach(cur => {
            rows.push({
                '#': '', 'Date': '', 'Particular': `${cur} Totals`,
                'TX ID': '', 'Type': '', 'Currency': cur,
                'Credit': totals[cur].credit, 'Debit': totals[cur].debit,
                'Agent': `Balance: ${totals[cur].balance}`, 'Notes': ''
            });
        });

        const ws = XLSX.utils.json_to_sheet(rows);
        const colWidths = Object.keys(rows[0]).map(key => ({
            wch: Math.max(key.length, ...rows.map(r => String(r[key] || '').length)) + 2
        }));
        ws['!cols'] = colWidths;

        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'Ledger');
        const fileName = `Ledger_${dateRange.range.replace(/\s/g, '_')}_${format(new Date(), 'dd-MMM-yyyy')}.xlsx`;
        XLSX.writeFile(wb, fileName);
        toast.success(`Downloaded ledger with ${filtered.length} entries`);
    };

    const shareOnWhatsApp = () => {
        const lines = [
            `­ƒôè *MoneyFlow Ledger Report*`,
            `Period: ${dateRange.range}`,
            `Generated: ${format(new Date(), 'dd MMM yyyy HH:mm')}`,
            `ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ`,
            `*Currency Summary:*`,
            ...displayCurrencies
                .filter(cur => totals[cur].credit > 0 || totals[cur].debit > 0)
                .map(cur => `${cur}: Credit ${fmt(totals[cur].credit)} | Debit ${fmt(totals[cur].debit)} | Balance ${fmt(totals[cur].balance)}`),
            `ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ`,
            `*Recent Entries (${Math.min(filtered.length, 20)} of ${filtered.length}):*`,
            ...filtered.slice(0, 20).map((r, i) =>
                `${i + 1}. ${r._date ? format(new Date(r._date), 'dd MMM') : 'ÔÇö'} | ${r.particular} | ${r.currency} ${r.credit > 0 ? '+' + fmt(r.credit) : '-' + fmt(r.debit)}`
            ),
            ``,
            `_MoneyFlow ERP_`,
        ];
        const text = encodeURIComponent(lines.join('\n'));
        window.open(`https://wa.me/?text=${text}`, '_blank');
    };

    const typeBadge = (type) => {
        if (type === 'transaction') return <span className="badge badge-completed" style={{ fontSize: 10, padding: '2px 8px' }}>TXN</span>;
        if (type === 'income') return <span className="badge" style={{ background: 'rgba(0,200,150,0.15)', color: 'var(--brand-accent)', fontSize: 10, padding: '2px 8px' }}>CR</span>;
        return <span className="badge" style={{ background: 'rgba(255,84,112,0.15)', color: 'var(--status-failed)', fontSize: 10, padding: '2px 8px' }}>DR</span>;
    };

    const resetFilters = () => {
        setDateRange({ range: 'All Time', customFrom: '', customTo: '' });
        setSearch('');
        setTypeFilter(['income', 'expense']);
        setCurrencyFilter('All');
    };

    const activeFilterCount = [
        dateRange.range !== 'All Time',
        search,
        currencyFilter !== 'All',
        typeFilter.length !== 2
    ].filter(Boolean).length;

    if (loading) {
        return (
            <Layout title="Ledger">
                <div className="loading-screen" style={{ minHeight: '60vh' }}>
                    <div className="spinner" /><p>Loading ledgerÔÇª</p>
                </div>
            </Layout>
        );
    }

    return (
        <Layout title="Reports ÔÇö Financial Ledger">

            {/* ÔöÇÔöÇ Ledger Summary ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            <div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '1.2px', color: 'var(--text-muted)', marginBottom: 12 }}>
                Ledger Summary ÔÇö {dateRange.range}
            </div>
            <div className="stats-grid" style={{ marginBottom: 32 }}>
                {displayCurrencies.map(cur => {
                    const t = totals[cur];
                    const colors = { SAR: '#4a9eff', AED: 'var(--brand-gold)', INR: '#a78bfa' };
                    const col = colors[cur];
                    return (
                        <div key={cur} className="card" style={{ padding: '24px 20px', border: `1px solid ${col}40`, position: 'relative', overflow: 'hidden' }}>
                            <div style={{ position: 'absolute', top: 0, left: 0, width: 4, height: '100%', background: col }}></div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-muted)', textTransform: 'uppercase' }}>{cur} Native Balance</span>
                                    <span style={{ fontSize: 13, fontWeight: 800, color: col }}>{cur}</span>
                                </div>
                                <div style={{ fontSize: 'clamp(24px, 2.8vw, 32px)', fontWeight: 900, color: col, letterSpacing: '-0.5px', margin: '4px 0' }}>
                                    {t.balance >= 0 ? '' : '-'}{fmt(Math.abs(t.balance))}
                                </div>
                                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, paddingTop: 12, borderTop: '1px solid var(--border-color)' }}>
                                    <div>
                                        <div style={{ fontSize: 10, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: 2 }}>Total Credit</div>
                                        <div style={{ color: 'var(--brand-accent)', fontWeight: 700, fontSize: 14 }}>{fmt(t.credit)}</div>
                                    </div>
                                    <div>
                                        <div style={{ fontSize: 10, color: 'var(--text-muted)', textTransform: 'uppercase', marginBottom: 2 }}>Total Debit</div>
                                        <div style={{ color: 'var(--status-failed)', fontWeight: 700, fontSize: 14 }}>{fmt(t.debit)}</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* ÔöÇÔöÇ Filter Bar ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            <FilterBar showClearAll onClearAll={resetFilters} activeFilterCount={activeFilterCount}>
                <DateRangeFilter
                    value={dateRange}
                    onChange={setDateRange}
                />
                <TypeFilter
                    value={typeFilter}
                    onChange={setTypeFilter}
                    options={TYPE_OPTIONS}
                    type="checkboxes"
                    multiSelect
                />
                <SearchInput
                    value={search}
                    onChange={setSearch}
                    placeholder="Search particulars..."
                />
                <CurrencyFilter
                    value={currencyFilter}
                    onChange={setCurrencyFilter}
                    currencies={['All', 'SAR', 'AED', 'INR']}
                />
                <div className="flex gap-2 ml-auto">
                    <button className="btn btn-outline" onClick={exportToExcel} style={{ whiteSpace: 'nowrap' }}>
                        <Download size={16} /> Excel
                    </button>
                    <button
                        className="btn btn-sm"
                        style={{ background: '#25D366', color: '#fff', border: 'none', whiteSpace: 'nowrap', display: 'flex', alignItems: 'center', gap: 6 }}
                        onClick={shareOnWhatsApp}
                        title="Share on WhatsApp"
                    >
                        <MessageCircle size={15} /> WhatsApp
                    </button>
                </div>
            </FilterBar>

            {/* ÔöÇÔöÇ Ledger Table ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
            {filtered.length === 0 ? (
                <div className="empty-state card">
                    <FileSpreadsheet size={40} />
                    <p>No entries found for the selected filters.</p>
                </div>
            ) : (
                <div className="card">
                    <div className="card-header">
                        <div>
                            <div className="card-title">Ledger</div>
                            <div className="card-subtitle">{filtered.length} entries ÔÇö {dateRange.range}</div>
                        </div>
                    </div>
                    <div className="table-wrapper">
                        <table className="data-table" style={{ fontSize: 13 }}>
                            <thead>
                                <tr>
                                    <th style={{ width: 40 }}>#</th>
                                    <th style={{ width: 100 }}>Date</th>
                                    <th style={{ width: 80 }}>Type</th>
                                    <th>Particular</th>
                                    <th style={{ width: 90 }}>Currency</th>
                                    <th style={{ textAlign: 'right', color: 'var(--brand-accent)', width: 140 }}>Credit</th>
                                    <th style={{ textAlign: 'right', color: 'var(--status-failed)', width: 140 }}>Debit</th>
                                    <th style={{ textAlign: 'right', width: 160 }}>Balance</th>
                                    <th style={{ width: 200 }}>Notes</th>
                                </tr>
                            </thead>
                            <tbody>
                                {entriesWithBalance.map((r, i) => (
                                    <tr key={r._id}>
                                        <td style={{ color: 'var(--text-muted)', fontSize: 11 }}>{i + 1}</td>
                                        <td style={{ color: 'var(--text-muted)', fontSize: 12, whiteSpace: 'nowrap' }}>
                                            {r._date ? format(new Date(r._date), 'dd MMM yy') : 'ÔÇö'}
                                        </td>
                                        <td>{typeBadge(r._type)}</td>
                                        <td style={{ fontWeight: 500, maxWidth: 220 }}>
                                            {r.txId && <span style={{ color: 'var(--brand-accent)', fontSize: 11, marginRight: 4 }}>#{r.txId}</span>}
                                            {r.particular}
                                        </td>
                                        <td>
                                            <span style={{
                                                fontSize: 11, fontWeight: 700, padding: '2px 6px', borderRadius: 4,
                                                background: r.currency === 'SAR' ? 'rgba(74,158,255,0.1)' :
                                                    r.currency === 'AED' ? 'rgba(245,166,35,0.1)' : 'rgba(167,139,250,0.1)',
                                                color: r.currency === 'SAR' ? '#4a9eff' :
                                                    r.currency === 'AED' ? 'var(--brand-gold)' : '#a78bfa'
                                            }}>{r.currency}</span>
                                        </td>
                                        <td style={{ textAlign: 'right', fontWeight: 600, color: r.credit > 0 ? 'var(--brand-accent)' : 'var(--text-muted)', fontVariantNumeric: 'tabular-nums' }}>
                                            {r.credit > 0 ? fmt(r.credit) : 'ÔÇö'}
                                        </td>
                                        <td style={{ textAlign: 'right', fontWeight: 600, color: r.debit > 0 ? 'var(--status-failed)' : 'var(--text-muted)', fontVariantNumeric: 'tabular-nums' }}>
                                            {r.debit > 0 ? fmt(r.debit) : 'ÔÇö'}
                                        </td>
                                        <td style={{
                                            textAlign: 'right', fontWeight: 700, fontVariantNumeric: 'tabular-nums',
                                            color: r.runningBalance >= 0 ? 'var(--text-primary)' : 'var(--status-failed)'
                                        }}>
                                            {fmt(r.runningBalance)} <span style={{ fontSize: 10, color: 'var(--text-muted)' }}>{r.currency}</span>
                                        </td>
                                        <td style={{ color: 'var(--text-muted)', fontSize: 11, maxWidth: 160, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                            {r.notes || 'ÔÇö'}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                            <tfoot>
                                {displayCurrencies.map(cur => {
                                    const t = totals[cur];
                                    if (t.credit === 0 && t.debit === 0) return null;
                                    const colors = { SAR: '#4a9eff', AED: 'var(--brand-gold)', INR: '#a78bfa' };
                                    return (
                                        <tr key={cur} style={{ borderTop: cur === 'SAR' ? '2px solid var(--border-color)' : undefined }}>
                                            <td colSpan={4} style={{ textAlign: 'right', fontWeight: 700, color: colors[cur] }}>
                                                {cur} TOTAL
                                            </td>
                                            <td></td>
                                            <td style={{ textAlign: 'right', fontWeight: 800, color: 'var(--brand-accent)', fontVariantNumeric: 'tabular-nums' }}>
                                                {fmt(t.credit)}
                                            </td>
                                            <td style={{ textAlign: 'right', fontWeight: 800, color: 'var(--status-failed)', fontVariantNumeric: 'tabular-nums' }}>
                                                {fmt(t.debit)}
                                            </td>
                                            <td style={{ textAlign: 'right', fontWeight: 800, color: t.balance >= 0 ? colors[cur] : 'var(--status-failed)', fontVariantNumeric: 'tabular-nums' }}>
                                                {fmt(t.balance)} <span style={{ fontSize: 10 }}>{cur}</span>
                                            </td>
                                            <td></td>
                                        </tr>
                                    );
                                })}
                            </tfoot>
                        </table>
                    </div>
                </div>
            )}
        </Layout>
    );
}

import { useState, useEffect, useRef } from 'react';
import { dbService } from '../lib/appwrite';
import { ledgerService } from '../lib/ledgerService';
import Layout from '../components/Layout';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import {
    Plus, X, Pencil, Trash2, Download
} from 'lucide-react';
import { format } from 'date-fns';
import * as XLSX from 'xlsx';

// Filter components
import { SearchInput, DateRangeFilter, FilterBar } from '../components/filters';
import { applyDateRange, round2 } from '../utils/filterHelpers';
import { TRANSACTION_STATUSES } from '../constants';

const START_TX_NUM = 20261;
const genTxId = (existingTxs) => {
    let max = START_TX_NUM - 1;
    for (const tx of existingTxs) {
        const n = parseInt(tx.tx_id, 10);
        if (!isNaN(n) && n > max) max = n;
    }
    return String(max + 1);
};

const statusBadge = (s) => {
    const cfg = TRANSACTION_STATUSES.find(x => x.value === s) || TRANSACTION_STATUSES[0];
    return <span className={`badge ${cfg.badge}`}>{cfg.label}</span>;
};

const EMPTY = {
    client_name: '',
    inr_requested: '',
    collected_currency: 'SAR',
    collected_amount: '',
    collection_rate: '',
    sar_to_aed_rate: '',
    actual_aed: '',
    aed_to_inr_rate: '',
    actual_inr_distributed: '',
    profit_aed: '',
    profit_inr: '',
    notes: '',
    status: '',
    collection_agent_id: '',
    collection_agent_name: '',
    conversion_agent_id: '',
    conversion_agent_name: '',
    distributor_id: '',
    distributor_name: '',
};

export default function TransactionsPage() {
    const { role, user } = useAuth();
    const isAdmin = role === 'admin';
    const isCollector = role === 'collector' || isAdmin;
    const isCollectorOnly = role === 'collector';

    const [txs, setTxs] = useState([]);
    const [agents, setAgents] = useState([]);
    const [settings, setSettings] = useState({ min_sar_rate: 0, min_aed_rate: 0 });
    const [search, setSearch] = useState('');
    const [dateRange, setDateRange] = useState({ range: 'All Time', customFrom: '', customTo: '' });
    const [_loading, setLoading] = useState(true);
    const [modal, setModal] = useState(false);
    const [editTx, setEditTx] = useState(null);
    const [form, setForm] = useState(EMPTY);
    const [saving, setSaving] = useState(false);
    const isSavingRef = useRef(false);

    const fetchAll = async () => {
        setLoading(true);
        try {
            const [txRes, agRes, sRes] = await Promise.all([
                dbService.listTransactions(),
                dbService.listAgents(),
                dbService.getSettings(),
            ]);
            setTxs(txRes.documents);
            setAgents(agRes.documents);
            setSettings(sRes);
        } catch (e) { toast.error('Failed to load: ' + e.message); }
        finally { setLoading(false); }
    };

    useEffect(() => { fetchAll(); }, []);

    // ÔöÇÔöÇ Calculations ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
    const calculateProfit = (tx, sarToAed, aedToInr, distributedInr) => {
        let aedValue = 0;
        if (tx.collected_currency === 'AED') {
            aedValue = tx.collected_amount;
        } else {
            aedValue = tx.collected_amount * (parseFloat(sarToAed) || 0);
        }
        const aedCostOfInr = ((parseFloat(distributedInr) || 0) / 1000) * (parseFloat(aedToInr) || 0);
        return (aedValue - aedCostOfInr).toFixed(2);
    };

    // Calculate INR profit from rate spread: (actual_rate - min_rate) / 1000 * inr_requested
    const calcProfitInr = (collectionRate, currency, inrRequested) => {
        const minRate = currency === 'AED' ? (settings.min_aed_rate || 0) : (settings.min_sar_rate || 0);
        const rate = parseFloat(collectionRate) || 0;
        const inr = parseFloat(inrRequested) || 0;
        if (minRate <= 0 || rate <= minRate) return 0;
        return round2((rate - minRate) / 1000 * inr);
    };

    const handleSave = async (e) => {
        e.preventDefault();
        if (isSavingRef.current) return;

        if (!form.client_name || !form.inr_requested || !form.collection_agent_id || !form.collection_rate || !form.collected_amount || !form.distributor_id) {
            return toast.error('Please fill all required fields');
        }

        isSavingRef.current = true;
        setSaving(true);
        try {
            const payload = { ...form };

            // Use round2 for all amounts to avoid float issues
            payload.inr_requested = round2(form.inr_requested);
            payload.collected_amount = round2(form.collected_amount);

            // Clean optional floats
            const optionalFloats = ['collection_rate', 'sar_to_aed_rate', 'actual_aed', 'aed_to_inr_rate', 'actual_inr_distributed', 'profit_aed', 'profit_inr'];
            optionalFloats.forEach(f => {
                if (payload[f] === '' || payload[f] === undefined) {
                    delete payload[f];
                } else if (!isNaN(parseFloat(payload[f]))) {
                    payload[f] = round2(payload[f]);
                }
            });

            if (editTx) {
                if (isCollectorOnly) {
                    payload.edit_pending_approval = true;
                    await dbService.updateTransaction(editTx.$id, payload);
                    toast.success('Edit submitted ÔÇö awaiting admin approval');
                    // Optimistic: update tx in state
                    setTxs(prev => prev.map(t => t.$id === editTx.$id ? { ...t, ...payload } : t));
                } else {
                    payload.edit_pending_approval = false;

                    // ÔöÇÔöÇ Reverse all ledger entries for this transaction ÔöÇÔöÇ
                    await ledgerService.reverseEntry(editTx.$id, 'transaction', 'EDIT REVERSAL: ');

                    // ÔöÇÔöÇ Record new ledger entries based on NEW payload ÔöÇÔöÇ
                    const dist = agents.find(a => a.$id === payload.distributor_id);
                    if (dist && payload.status === 'completed') {
                        await ledgerService.recordEntry({
                            agent: dist,
                            amount: payload.inr_requested,
                            currency: 'INR',
                            type: 'credit', // Agent gave INR to client
                            reference_type: 'transaction',
                            reference_id: editTx.$id,
                            description: `TX #${payload.tx_id} - Outgoing INR for ${payload.client_name} (Revised)`
                        });
                    }

                    const colAgent = agents.find(a => a.$id === payload.collection_agent_id);
                    if (colAgent) {
                        await ledgerService.recordEntry({
                            agent: colAgent,
                            amount: payload.collected_amount,
                            currency: payload.collected_currency,
                            type: 'debit', // Agent received SAR from client
                            reference_type: 'transaction',
                            reference_id: editTx.$id,
                            description: `TX #${payload.tx_id} - Collected from ${payload.client_name} (Revised)`
                        });
                    }

                    if (payload.conversion_agent_id && (payload.status === 'pending_distribution' || payload.status === 'completed')) {
                        const convAgent = agents.find(a => a.$id === payload.conversion_agent_id);
                        if (convAgent) {
                            await ledgerService.recordEntry({
                                agent: convAgent,
                                amount: payload.collected_amount,
                                currency: payload.collected_currency,
                                type: 'debit', // Agent received SAR to convert
                                reference_type: 'transaction',
                                reference_id: editTx.$id,
                                description: `TX #${payload.tx_id} - Conversion for ${payload.client_name} (Revised)`
                            });
                        }
                    }

                    // ÔöÇÔöÇ Calculate INR profit from rate spread ÔöÇÔöÇ
                    const profitInr = calcProfitInr(payload.collection_rate, payload.collected_currency, payload.inr_requested);
                    if (profitInr > 0) payload.profit_inr = profitInr;

                    await dbService.updateTransaction(editTx.$id, payload);
                    toast.success('Transaction Updated successfully');
                    fetchAll(); // Refresh to ensure state is consistent
                }
            } else {
                if (!payload.distributor_id) {
                    isSavingRef.current = false;
                    setSaving(false);
                    return toast.error('Please select a Distributor');
                }

                // ÔöÇÔöÇ Min rate enforcement ÔöÇÔöÇ
                const currency = form.collected_currency;
                const minRate = currency === 'AED' ? (settings.min_aed_rate || 0) : (settings.min_sar_rate || 0);
                const collRate = parseFloat(form.collection_rate) || 0;
                if (minRate > 0 && collRate < minRate) {
                    isSavingRef.current = false;
                    setSaving(false);
                    return toast.error(
                        `This amount can't be entered. Please check the rate and try again.`,
                        { duration: 5000 }
                    );
                }

                payload.tx_id = genTxId(txs);
                payload.creator_id = user.$id;
                payload.creator_name = user.name;
                payload.status = 'completed';
                payload.actual_inr_distributed = round2(payload.inr_requested);

                const created = await dbService.createTransaction(payload);

                // ÔöÇÔöÇ Update distributor balance and ledger ÔöÇÔöÇ
                const dist = agents.find(a => a.$id === payload.distributor_id);
                if (dist) {
                    await ledgerService.recordEntry({
                        agent: dist,
                        amount: payload.inr_requested,
                        currency: 'INR',
                        type: 'credit', // Agent gave INR to client
                        reference_type: 'transaction',
                        reference_id: created.$id,
                        description: `TX #${payload.tx_id} - Outgoing INR for ${payload.client_name}`
                    });
                }

                // ÔöÇÔöÇ Update collection agent's balance and ledger ÔöÇÔöÇ
                if (payload.collection_agent_id) {
                    const agent = agents.find(a => a.$id === payload.collection_agent_id);
                    if (agent) {
                        await ledgerService.recordEntry({
                            agent: agent,
                            amount: payload.collected_amount,
                            currency: payload.collected_currency,
                            type: 'debit', // Agent received SAR from client
                            reference_type: 'transaction',
                            reference_id: created.$id,
                            description: `TX #${payload.tx_id} - Collected from ${payload.client_name}`
                        });
                    }
                }

                // ÔöÇÔöÇ Update conversion agent's balance and ledger ÔöÇÔöÇ
                if (payload.conversion_agent_id) {
                    const convAgent = agents.find(a => a.$id === payload.conversion_agent_id);
                    if (convAgent) {
                        await ledgerService.recordEntry({
                            agent: convAgent,
                            amount: payload.collected_amount,
                            currency: payload.collected_currency,
                            type: 'debit', // Agent received SAR to convert
                            reference_type: 'transaction',
                            reference_id: created.$id,
                            description: `TX #${payload.tx_id} - Conversion for ${payload.client_name}`
                        });
                    }
                }

                toast.success('Transaction Logged');
                fetchAll(); // Refresh everything to be safe
            }
            setModal(false);
        } catch (e) { toast.error(e.message); }
        finally {
            isSavingRef.current = false;
            setSaving(false);
        }
    };

    const handleApproveEdit = async (tx) => {
        try {
            await dbService.updateTransaction(tx.$id, { edit_pending_approval: false });
            toast.success(`Edit approved for TX #${tx.tx_id}`);
            // Optimistic: update in state
            setTxs(prev => prev.map(t => t.$id === tx.$id ? { ...t, edit_pending_approval: false } : t));
        } catch (e) { toast.error('Approve failed: ' + e.message); }
    };

    const openEdit = (tx) => {
        setEditTx(tx);
        setForm({ ...tx });
        setModal(true);
    };

    const handleDelete = async (tx) => {
        if (!isAdmin) return toast.error('Only admins can delete transactions');
        if (!confirm(`Delete transaction #${tx.tx_id} for ${tx.client_name}? This cannot be undone.`)) return;
        try {
            // ÔöÇÔöÇ Reverse all ledger entries for this transaction ÔöÇÔöÇ
            await ledgerService.reverseEntry(tx.$id, 'transaction');

            await dbService.deleteTransaction(tx.$id);
            toast.success(`Transaction #${tx.tx_id} deleted`);
            fetchAll(); // Refresh to ensure state is consistent
        } catch (e) {
            toast.error('Delete failed: ' + e.message);
        }
    };

    const filtered = applyDateRange(txs, dateRange.range, dateRange.customFrom, dateRange.customTo).filter(tx =>
        tx.client_name?.toLowerCase().includes(search.toLowerCase()) ||
        tx.tx_id?.includes(search)
    );

    const exportToExcel = () => {
        if (filtered.length === 0) return toast.error('No transactions to export');
        const rows = filtered.map(tx => ({
            'TX ID': tx.tx_id || '',
            'Date': tx.$createdAt ? format(new Date(tx.$createdAt), 'dd-MM-yyyy HH:mm') : '',
            'Client Name': tx.client_name || '',
            'INR Requested': tx.inr_requested || 0,
            'Collected Currency': tx.collected_currency || '',
            'Collection Rate': tx.collection_rate || '',
            'Amount Collected': tx.collected_amount || 0,
            'Collection Agent': tx.collection_agent_name || '',
            'Distributor': tx.distributor_name || '',
            'INR Distributed': tx.actual_inr_distributed || 0,
            'Profit INR': tx.profit_inr || 0,
            'Status': tx.status || '',
            'Notes': tx.notes || '',
        }));
        const ws = XLSX.utils.json_to_sheet(rows);
        const colWidths = Object.keys(rows[0]).map(key => ({
            wch: Math.max(key.length, ...rows.map(r => String(r[key]).length)) + 2
        }));
        ws['!cols'] = colWidths;
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'Transactions');
        const fileName = `Transactions_${dateRange.range.replace(/\s/g, '_')}_${format(new Date(), 'dd-MMM-yyyy')}.xlsx`;
        XLSX.writeFile(wb, fileName);
        toast.success(`Downloaded ${filtered.length} transactions`);
    };

    // Derive min rate hint for form
    const minRateForCurrency = form.collected_currency === 'AED'
        ? (settings.min_aed_rate || 0)
        : (settings.min_sar_rate || 0);

    // Preview profit in form
    const previewProfit = form.collection_rate && form.inr_requested
        ? calcProfitInr(form.collection_rate, form.collected_currency, form.inr_requested)
        : 0;

    return (
        <Layout title="Transactions">
            <FilterBar>
                <DateRangeFilter
                    value={dateRange}
                    onChange={setDateRange}
                />
                <SearchInput
                    value={search}
                    onChange={setSearch}
                    placeholder="Search client or ID..."
                />
                <div className="flex gap-2 flex-wrap ml-auto">
                    {isAdmin && (
                        <button className="btn btn-outline" onClick={exportToExcel} title="Download as Excel">
                            <Download size={16} /> Excel
                        </button>
                    )}
                    {isCollector && (
                        <button className="btn btn-accent" onClick={() => { setForm(EMPTY); setEditTx(null); setModal(true); }}>
                            <Plus size={16} /> <span className="hide-on-mobile">New Transaction</span><span className="show-on-mobile">New</span>
                        </button>
                    )}
                </div>
            </FilterBar>

            <div className="card">
                <div className="table-wrapper">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th style={{ width: 100 }}>TX ID</th>
                                <th>Client</th>
                                <th style={{ textAlign: 'right', width: 140 }}>Requested</th>
                                <th style={{ textAlign: 'right', width: 160 }}>Amount</th>
                                <th>Agent</th>
                                {isAdmin && <th style={{ textAlign: 'right', width: 120 }}>Profit</th>}
                                {isAdmin && <th>Distributor</th>}
                                <th style={{ width: 120 }}>Status</th>
                                <th style={{ width: 100 }}>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filtered.map(tx => {
                                const profitCur = tx.collected_currency || 'SAR';
                                const profitVal = Number(tx.profit_inr) || 0;
                                return (
                                    <tr key={tx.$id} style={tx.edit_pending_approval ? { background: 'rgba(255,170,50,0.06)', outline: '1px solid rgba(255,170,50,0.25)' } : {}}>
                                        <td className="font-bold">
                                            #{tx.tx_id}
                                            {tx.edit_pending_approval && (
                                                <span style={{ marginLeft: 6, fontSize: 10, background: '#ffaa32', color: '#000', borderRadius: 4, padding: '1px 5px', fontWeight: 700 }}>PENDING EDIT</span>
                                            )}
                                        </td>
                                        <td>{tx.client_name}</td>
                                        <td className="currency inr" style={{ textAlign: 'right', fontWeight: 600 }}>Ôé╣{tx.inr_requested?.toLocaleString('en-IN')}</td>
                                        <td className={`currency ${tx.collected_currency?.toLowerCase()}`} style={{ textAlign: 'right', fontWeight: 600 }}>
                                            {tx.collected_amount?.toLocaleString()} <span style={{ fontSize: 10, opacity: 0.7 }}>{tx.collected_currency}</span>
                                        </td>
                                        <td>{tx.collection_agent_name || 'ÔÇö'}</td>
                                        {isAdmin && (
                                            <td style={{ textAlign: 'right', color: profitVal > 0 ? 'var(--brand-accent)' : 'var(--text-muted)', fontWeight: profitVal > 0 ? 700 : 400 }}>
                                                {profitVal > 0 ? `${profitVal.toLocaleString('en-IN')}` : 'ÔÇö'}
                                            </td>
                                        )}
                                        {isAdmin && (
                                            <td style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                                                {tx.distributor_name || 'ÔÇö'}
                                            </td>
                                        )}
                                        <td>{statusBadge(tx.status)}</td>
                                        <td>
                                            <div className="flex gap-2">
                                                {isCollector && (
                                                    <button className="btn btn-icon btn-sm" onClick={() => openEdit(tx)} title="Edit"><Pencil size={14} /></button>
                                                )}
                                                {isAdmin && tx.edit_pending_approval && (
                                                    <button className="btn btn-sm" style={{ background: '#22c55e', color: '#fff', border: 'none', fontWeight: 700, fontSize: 12 }} onClick={() => handleApproveEdit(tx)} title="Approve Edit">Ô£ô Approve</button>
                                                )}
                                                {isAdmin && (
                                                    <button className="btn btn-icon btn-sm btn-danger" onClick={() => handleDelete(tx)} title="Delete">
                                                        <Trash2 size={14} />
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Creation Modal */}
            {modal && (
                <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setModal(false)}>
                    <div className="modal">
                        <div className="modal-header">
                            <h3 className="modal-title">{editTx ? 'Edit Transaction' : 'New Transaction Request'}</h3>
                            <button className="close-btn" onClick={() => setModal(false)}><X size={20} /></button>
                        </div>
                        <form onSubmit={handleSave}>
                            <div className="modal-body">
                                <div className="form-group">
                                    <label className="form-label">Client Name</label>
                                    <input className="form-input" required value={form.client_name}
                                        onChange={e => setForm({ ...form, client_name: e.target.value })} />
                                </div>
                                <div className="form-row">
                                    <div className="form-group">
                                        <label className="form-label">INR Requested</label>
                                        <input className="form-input" type="number" required value={form.inr_requested}
                                            onChange={e => {
                                                const inr = parseFloat(e.target.value) || 0;
                                                const rate = parseFloat(form.collection_rate) || 0;
                                                const collected = rate > 0 ? (inr / 1000) * rate : form.collected_amount;
                                                setForm({ ...form, inr_requested: e.target.value, collected_amount: rate > 0 ? collected.toFixed(2) : form.collected_amount });
                                            }} />
                                    </div>
                                    <div className="form-group">
                                        <label className="form-label">Collection Agent</label>
                                        <select className="form-select" required value={form.collection_agent_id}
                                            onChange={e => {
                                                const a = agents.find(x => x.$id === e.target.value);
                                                setForm({
                                                    ...form,
                                                    collection_agent_id: e.target.value,
                                                    collection_agent_name: a?.name || '',
                                                    collected_currency: a?.currency || form.collected_currency
                                                });
                                            }}>
                                            <option value="">Select Agent</option>
                                            {agents.filter(a => a.type.startsWith('collection')).map(a => <option key={a.$id} value={a.$id}>{a.name} ({a.currency || 'SAR'})</option>)}
                                        </select>
                                    </div>
                                </div>
                                <div className="form-row">
                                    <div className="form-group">
                                        <label className="form-label">Collect In</label>
                                        <select className="form-select" value={form.collected_currency}
                                            onChange={e => setForm({ ...form, collected_currency: e.target.value })}>
                                            <option value="SAR">SAR</option>
                                            <option value="AED">AED</option>
                                        </select>
                                    </div>
                                    <div className="form-group">
                                        <label className="form-label">
                                            Collection Rate (per 1000 INR)
                                        </label>
                                        <input className="form-input" type="number" step="0.01" required value={form.collection_rate}
                                            placeholder="Enter rate"
                                            style={{
                                                borderColor: !editTx && form.collection_rate && minRateForCurrency > 0 && parseFloat(form.collection_rate) < minRateForCurrency
                                                    ? 'var(--status-failed)' : undefined
                                            }}
                                            onChange={e => {
                                                const rate = parseFloat(e.target.value) || 0;
                                                const inr = parseFloat(form.inr_requested) || 0;
                                                const collected = rate > 0 ? (inr / 1000) * rate : form.collected_amount;
                                                setForm({ ...form, collection_rate: e.target.value, collected_amount: rate > 0 ? collected.toFixed(2) : form.collected_amount });
                                            }} />
                                        {!editTx && form.collection_rate && minRateForCurrency > 0 && parseFloat(form.collection_rate) < minRateForCurrency && (
                                            <div style={{ fontSize: 11, color: 'var(--status-failed)', marginTop: 4 }}>
                                                ÔÜá´©Å This amount can't be entered
                                            </div>
                                        )}
                                    </div>
                                    <div className="form-group">
                                        <label className="form-label">Amount Collected ({form.collected_currency})</label>
                                        <input className="form-input" type="number" step="0.01" required value={form.collected_amount}
                                            readOnly style={{ backgroundColor: 'var(--bg-main)', opacity: 0.8 }} />
                                    </div>
                                </div>

                                {/* Profit Preview ÔÇö admin only */}
                                {isAdmin && !editTx && previewProfit > 0 && (
                                    <div style={{ background: 'rgba(0,200,150,0.08)', border: '1px solid rgba(0,200,150,0.2)', borderRadius: 8, padding: '10px 14px', marginBottom: 12 }}>
                                        <span style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                                            ­ƒôê Estimated Profit: <strong style={{ color: 'var(--brand-accent)' }}>{previewProfit.toLocaleString('en-IN')} {form.collected_currency}</strong>
                                            <span style={{ fontSize: 11, color: 'var(--text-muted)', marginLeft: 6 }}>
                                                (rate spread: {parseFloat(form.collection_rate) - minRateForCurrency} ├ù {form.inr_requested}/1000)
                                            </span>
                                        </span>
                                    </div>
                                )}

                                <div className="form-row">
                                    <div className="form-group">
                                        <label className="form-label">Distributor (Auto-Deducts)</label>
                                        <select className="form-select" required value={form.distributor_id}
                                            onChange={e => {
                                                const a = agents.find(x => x.$id === e.target.value);
                                                setForm({
                                                    ...form,
                                                    distributor_id: e.target.value,
                                                    distributor_name: a?.name || ''
                                                });
                                            }}>
                                            <option value="">Select Distributor</option>
                                            {agents.filter(a => a.type === 'distributor').map(a => <option key={a.$id} value={a.$id}>{a.name} (Bal: Ôé╣{round2(a.inr_balance || 0).toLocaleString('en-IN')})</option>)}
                                        </select>
                                    </div>
                                </div>
                                <div className="form-group">
                                    <label className="form-label">Notes</label>
                                    <textarea className="form-textarea" value={form.notes}
                                        onChange={e => setForm({ ...form, notes: e.target.value })} />
                                </div>
                            </div>
                            <div className="modal-footer">
                                <button type="button" className="btn btn-outline" onClick={() => setModal(false)}>Cancel</button>
                                <button type="submit" className="btn btn-accent" disabled={saving}>Save Transaction</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </Layout>
    );
}
